/* artifacts q14 (69 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q14"]=window.__LIBQ["tien-nghich"]["q14"]||{};window.__LIBQ["tien-nghich"]["q14"]["artifacts"]={"updatedAt":"2026-07-17","count":69,"artifacts":[{"id":"ba-huong-hoa-hac-long","name":"Ba hương hỏa hắc long","cn":"三香火黑龍","aliases":[],"category":"khac","categoryLabel":"Linh thú / Hương hỏa thú","phamCap":"Không rõ (cuồng phong hủy diệt tinh không)","soHuu":["Thiên Triệu Thượng Sư"],"trangThai":"duoc-tha","blurb":"Ba hương hỏa hắc long là ba con hắc long thuộc tộc hắc long, lúc nhỏ bị Thiên Triệu Thượng Sư bắt và tế luyện thành hương hỏa thú. Khi đối đầu Vương Lâm, chúng nhận ra kim quang tiên lực trong truyền thừa linh hồn, sợ hãi phun máu đen bái lạy, sau đó được Vương Lâm tha mạng và phóng thích.","detail":"Ba hương hỏa hắc long vốn thuộc tộc hắc long, lúc nhỏ bị Thiên Triệu Thượng Sư bắt và tế luyện thành hương hỏa thú phục vụ chiến đấu. Trong truyền thừa linh hồn của tộc hắc long có ghi nhớ về kim quang tiên lực — biểu tượng của bá chủ thế giới chúng. Tại trận chiến với Vương Lâm (@c1455), Thiên Triệu Thượng Sư điều khiển ba hắc long tấn công, nhưng khi tiếp xúc kim quang tiên lực của Vương Lâm, chúng sợ hãi phun máu đen và đồng loạt bái lạy, không dám phản kháng. Sau đó (@c1457), Vương Lâm không giết mà túm ném chúng đi cho tự do, cảnh cáo rằng nếu giết một tu sĩ giới nội sẽ bị hủy hồn phách. Ba hắc long vui mừng bay vào tinh không.","congNang":["Cuồng phong hủy diệt, uy lực đủ khiến tinh không sụp đổ nứt nẻ (@c1455)","Truyền thừa linh hồn ghi nhớ kim quang tiên lực, gặp kim quang thì bản năng sợ hãi phun máu đen, đồng loạt bái lạy quy phục (@c1455)"],"dacDiem":"Tộc hắc long, truyền thừa linh hồn nhớ kim quang tiên lực — gặp người mang kim quang tiên lực thì bản năng sợ hãi quy phục, nhận đó là bá chủ thế giới của tộc mình.","chuSoHuu":[{"ten":"Thiên Triệu Thượng Sư","tuChuong":"@c1455","denChuong":"@c1455","cachCoDuoc":"Bắt và tế luyện từ nhỏ","trangThai":"bi-diet"}],"tabs":{"tienTrinh":[{"chuong":"@c1455","loai":"dùng","importance":"major","giaiDoan":"Bị khuất phục và bị diệt","text":"Thiên Triệu Thượng Sư điều khiển ba hắc long tấn công Vương Lâm. Khi gặp kim quang tiên lực, chúng sợ hãi phun máu đen đồng loạt bái lạy. Sau đó hồn phách hương hỏa bị tiên lôi đánh tan.","anchor":"cho dù chúng thuộc tộc hắc long thì dưới kim quang này mà dám phản kháng nửa điểm thì sẽ bị diệt tộc!"},{"chuong":"@c1457","loai":"doi-chu","importance":"normal","giaiDoan":"Được Vương Lâm phóng thích","text":"Bị Vương Lâm túm ném đi cho tự do, cảnh cáo nếu giết một tu sĩ giới nội sẽ hủy hồn phách. Vui mừng bay vào tinh không biến mất.","anchor":"Ngươi được tự do! Nhưng nếu ngươi giết tu sĩ giới nội dù chỉ một người, thì ta sẽ hủy diệt hồn phách của ngươi"}]},"nguon":["@c1455","@c1457"],"uyLuc":"Cuồng phong của ba hắc long cực kỳ kinh khủng, đủ sức khiến tinh không sụp đổ nứt nẻ (@c1455)."},{"id":"cay-cung-vuong-lam","name":"Cây cung (Vương Lâm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cây cung được Vương Lâm lấy ra từ trong thân thể khi đối đầu Long Bàn Tử tại tổng bộ Tu Chân Liên Minh.","detail":"Xuất hiện từ trong thân Vương Lâm sau khi Dịch Linh Ấn bị Sơn Hà Đồ phản kích, chuẩn bị chiến đấu tiếp.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1458","denChuong":"","cachCoDuoc":"Lấy ra từ trong thân thể","trangThai":"dang-co"}],"congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1458","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm rút cung đối đầu Long Bàn Tử","text":"Vương Lâm lấy ra cây cung từ trong thân thể sau khi bị Sơn Hà Đồ phản kích, chuẩn bị chiến đấu tiếp.","anchor":"bất ngờ từ trong thân thể hắn xuất hiện một cây cung"}]},"nguon":["@c1458"]},{"id":"ngon-tay-tro-bay-mau","name":"Ngón tay trỏ bảy màu","cn":"","category":"khac","categoryLabel":"Vật bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ngón tay trỏ khổng lồ dài mười trượng phát ánh sáng bảy màu, lơ lửng trước mi tâm Thanh Thủy, không ngừng hấp thụ sát lục bổn nguyên từ mi tâm hắn. Vương Lâm nhận định đây là nguồn gốc của tất cả mọi việc.","detail":"Dài chừng mười trượng, lơ lửng trước mi tâm Thanh Thủy cách ba tấc, liên tục hấp thụ sát lục bổn nguyên biểu hiện dưới dạng tơ đỏ như máu. Xuất xứ chưa rõ, có thể liên quan tới thân ảnh bí ẩn trong ánh sáng bảy màu đã quan sát Thanh Thủy từ thuở thiếu niên. Vương Lâm đánh giá ngón trỏ này chính là nguồn gốc của toàn bộ âm mưu.","congNang":["Hấp thụ sát lục bổn nguyên từ mi tâm Thanh Thủy"],"nguon":["@c1461"]},{"id":"muoi-cai-coc-phong-an","name":"Mười cái cọc phong ấn","cn":"","category":"phap-bao","categoryLabel":"Trận cụ","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Mười cái cọc nhọn phát ánh sáng bảy màu, đóng chặt thân thể Thanh Thủy lên vách núi, là bộ phận cốt lõi của trận pháp mười vạn ngọn núi.","detail":"Chín cọc nhọn phát ánh sáng bảy màu đóng chặt thân Thanh Thủy lên vách núi đỉnh núi cao nhất, cọc thứ mười ẩn giấu dưới tóc bên phải thiên linh. Là bộ phận then chốt của trận pháp mười vạn ngọn núi, phong ấn thân thể Thanh Thủy để trận pháp vận hành luyện sát lục bổn nguyên.","congNang":["Phong ấn thân thể Thanh Thủy trên vách núi"],"nguon":["@c1461"]},{"id":"bon-cay-coc-phong-an-thanh-thuy","name":"Bốn cây cọc phong ấn Thanh Thủy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thanh Thủy"],"trangThai":"da-rut","blurb":"Bốn cây cọc phong ấn đóng trên thân thể Thanh Thủy tại Thất Thải Giới, lần lượt phong ấn trái tim, gân cốt và thần thức. Khi bị rút ra, mỗi cọc tự động phản kích người rút với sát lực nặng nề; Vương Lâm rút cả bốn thành công nhưng chịu trọng thương, phun máu hai lần.","detail":"Bốn cây cọc được đóng trên bốn vị trí trên thân thể Thanh Thủy: cọc thứ nhất trên ngực phong ấn trái tim, cọc thứ hai trên cổ họng phong ấn gân cốt, cọc thứ ba và thứ tư lần lượt trên cánh tay trái và cánh tay phải phong ấn thần thức. Mỗi cọc khi bị rút ra đều kích hoạt cơ chế phản lực tấn công người rút: cọc phong ấn trái tim gây đau nhức tim dữ dội, cọc phong ấn gân cốt kéo căng gân cốt, hai cọc phong ấn thần thức tấn công thần thức gây trọng thương. Vương Lâm lần lượt rút cả bốn cây cọc, mỗi lần đều gánh chịu phản lực nặng nề, phun máu hai lần trong quá trình giải phong ấn, cuối cùng giải phóng hoàn toàn cho Thanh Thủy.","congNang":["Phong ấn trái tim — cọc đóng trên ngực, khi rút gây đau nhức tim dữ dội cho người rút @c1464","Phong ấn gân cốt — cọc đóng trên cổ họng, khi rút kéo căng gân cốt người rút @c1464","Phong ấn thần thức — hai cọc đóng trên hai cánh tay, khi rút tấn công thần thức người rút gây trọng thương @c1464","Phản lực tự động tấn công người rút cọc, mỗi cọc kích hoạt một dạng phản kích khác nhau @c1464"],"dacDiem":"Mỗi cọc phong ấn một bộ phận khác nhau trên cơ thể, khi bị rút ra tự động phản kích người rút với hình thức sát thương tương ứng bộ phận bị phong ấn.","chuSoHuu":[{"ten":"Thanh Thủy","tuChuong":"@c1464","denChuong":"","cachCoDuoc":"Bị đóng lên người để phong ấn","trangThai":"da-rut"}],"tabs":{"tienTrinh":[{"chuong":"@c1464","loai":"xuat-hien","importance":"major","giaiDoan":"Bị Vương Lâm rút cả bốn cọc","text":"Vương Lâm rút lần lượt bốn cây cọc phong ấn trên người Thanh Thủy, giải phóng trái tim, gân cốt và thần thức. Mỗi cọc gây phản lực: cọc 1 gây đau tim, cọc 2 kéo căng gân cốt, cọc 3-4 tấn công thần thức khiến Vương Lâm phun máu hai lần.","anchor":"Cây cọc thứ nhất này chính là phong ấn trái tim của hắn"}]},"nguon":["@c1464"],"uyLuc":"Phản lực của bốn cọc đủ mạnh để khiến Vương Lâm chịu trọng thương, phun máu hai lần trong quá trình rút cọc."},{"id":"dao-qua-mau-vang","name":"Đạo quả màu vàng","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sở hữu","blurb":"Đạo quả rất lớn màu vàng, được thân ảnh bảy màu lấy ra từ sương mù bảy màu trong Thất Thải Giới rồi bẻ cành tặng cho Vương Lâm làm lễ vật sau khi rút cọc phong ấn (@c1465).","detail":"Đạo quả màu vàng xuất hiện bên trong đám sương mù bảy màu của Thất Thải Giới. Thân ảnh bảy màu chủ động lấy quả này ra, bẻ cành rồi trao cho Vương Lâm với tư cách lễ vật đáp tạ việc Vương Lâm rút cọc phong ấn. Quả có hình dạng rất lớn, màu vàng, vẫn còn dính cành. Tính đến mốc hiện có, công dụng cụ thể của đạo quả chưa được hé lộ.","congNang":["Chưa hé lộ công dụng cụ thể"],"chuSoHuu":[{"ten":"Thân ảnh bảy màu","tuChuong":"@c1465","denChuong":"@c1465","cachCoDuoc":"Nguồn gốc từ sương mù Thất Thải Giới","trangThai":"đã tặng"},{"ten":"Vương Lâm","tuChuong":"@c1465","denChuong":"","cachCoDuoc":"Được thân ảnh bảy màu tặng làm lễ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1465","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện và đổi chủ","text":"Thân ảnh bảy màu lấy từ sương mù bảy màu trong Thất Thải Giới, bẻ cành ra tặng cho Vương Lâm làm lễ vật sau khi rút cọc phong ấn cho Thanh Thủy.","anchor":"chỉ thấy một đạo quả màu vàng rất lớn chậm rãi từ bên trong đám sương mù hiện ra"}]},"nguon":["@c1465"],"dacDiem":"Hình dạng rất lớn, màu vàng, có cành dính vào, hiện ra từ bên trong sương mù bảy màu của Thất Thải Giới."},{"id":"muoi-cay-coc-bay-mau","name":"Mười cây cọc bảy màu (phong ấn Thanh Thủy)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"còn 2 cọc chưa rút","blurb":"Mười cây cọc bảy màu được đóng trên thân Thanh Thủy, mỗi cọc phong ấn một phần cơ thể hoặc sức mạnh của nàng. Tính tới mốc gần nhất, Vương Lâm đã rút được tám cọc, còn lại hai đạo phong ấn cuối cùng được cho là khó gỡ hơn rất nhiều.","detail":"Mười cây cọc bảy màu là một tổ hợp phong ấn đóng trên khắp thân thể Thanh Thủy, mỗi cọc trấn phong một phần khác nhau của cơ thể hoặc năng lực. Cọc thứ năm phong ấn nguyên thần, đóng ở vùng đan điền. Cọc thứ sáu và thứ bảy đóng ở hai chân. Cọc thứ tám khác biệt với các cọc còn lại: nó đâm gần thiên linh cái, chỉ thò ra khoảng hai tấc, và mục đích không phải phong ấn sức mạnh mà là mở ra luân hồi của Thanh Thủy. Khi Vương Lâm rút cọc thứ tám, vô số ký ức vặn vẹo tràn vào đầu người rút. Tại mốc @c1465, Vương Lâm lần lượt rút cọc 5, đồng thời rút cọc 6–7, và rút cọc 8. Hai đạo phong ấn cuối cùng vẫn chưa được gỡ bỏ.","congNang":["Mỗi cọc phong ấn một phần cơ thể hoặc sức mạnh của Thanh Thủy — cọc thứ năm phong ấn nguyên thần tại đan điền @c1465","Cọc thứ tám không phải phong ấn mà dùng để mở ra luân hồi của Thanh Thủy; khi rút, vô số ký ức vặn vẹo tràn vào đầu người rút @c1465"],"tabs":{"tienTrinh":[{"chuong":"@c1465","loai":"dùng","importance":"major","giaiDoan":"Rút cọc 5–8, còn 2 cọc cuối","text":"Vương Lâm rút cọc 5 (đan điền, phong ấn nguyên thần), cọc 6-7 (hai chân) đồng thời, cọc 8 (gần thiên linh, mở ra luân hồi). Mỗi lần rút chịu phản lực kinh khủng. Thanh Thủy tách khỏi ngọn núi, hôn mê. Còn hai đạo phong ấn cuối cùng chưa được gỡ, được nói là khó hơn rất nhiều.","anchor":"Cây cọc thứ năm này phong ấn nguyên thần của hắn"}]},"nguon":["@c1465"],"dacDiem":"Mười cọc có bảy màu sắc, đóng rải rác trên thân Thanh Thủy ở các vị trí khác nhau; cọc thứ tám chỉ thò ra hai tấc gần thiên linh cái, bản chất khác hẳn các cọc phong ấn thông thường."},{"id":"viem-long-huyet","name":"Viêm long huyết","cn":"","category":"dan-duoc","categoryLabel":"Đan dược / Dược liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Bầu rượu màu xanh chứa viêm long huyết do Lão Tổ Cấm Địa Chu Tước cho Vương Lâm, được dùng thay rượu mạnh cho Thanh Thủy uống để chịu đựng đau đớn khi rút cọc phong ấn.","detail":"Viêm long huyết có mùi tanh nhưng vị ngọt và cực mạnh. Thanh Thủy nhận xét đủ mạnh để thay rượu. Nguồn gốc từ lão Chu Tước trao cho Vương Lâm trước đó.","congNang":["Dùng như chất kích thích giúp chịu đựng cơn đau cực hạn khi rút cọc phong ấn từ huyết quản"],"chuSoHuu":[{"ten":"Lão Tổ Cấm Địa Chu Tước","tuChuong":"@c1466","denChuong":"","cachCoDuoc":"Nguồn gốc (trao cho Vương Lâm)","trangThai":"da-cho"},{"ten":"Vương Lâm","tuChuong":"@c1466","denChuong":"@c1466","cachCoDuoc":"Được lão Chu Tước cho","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1466","loai":"dùng","importance":"normal","giaiDoan":"Cho Thanh Thủy uống thay rượu mạnh","text":"Vương Lâm lấy bầu viêm long huyết mà lão Chu Tước đã cho, đưa Thanh Thủy uống để chịu đựng cơn đau khi rút cây cọc cuối cùng từ huyết quản.","anchor":"Một cái bầu rượu màu xanh xuất hiện, nhưng đây không phải là rượu, mà là viêm long huyết mà lão Chu Tước đã cho hắn"}]},"nguon":["@c1466"]},{"id":"hac-kiem-bon-nguyen","name":"Hắc kiếm bổn nguyên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo bổn nguyên","phamCap":"Pháp bảo bổn nguyên bước thứ ba","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Hắc kiếm bổn nguyên là pháp bảo bước thứ ba do Thanh Thủy dùng sát lục bổn nguyên ngưng tụ thành khi phá không môn, sau đó thu toàn bộ hồn phách người bị mình giết (trừ Hàm Yên) vào kiếm rồi tặng lại Vương Lâm. Đây là pháp bảo bổn nguyên đầu tiên của tu sĩ bước thứ ba, cực kỳ hiếm gặp — ngay cả các đại năng hàng đầu đều không ngưng tụ nổi.","detail":"Khi Thanh Thủy phá không môn, toàn bộ sát lục bổn nguyên tích lũy cả đời được ngưng tụ thành một thanh hắc kiếm, lấy sát lục làm nền tảng phá tan không môn. Sau đó Thanh Thủy thu nạp toàn bộ hồn phách của những người bị mình giết trong đời (ngoại trừ Hàm Yên) vào bên trong kiếm, rồi tặng lại cho Vương Lâm. Thanh kiếm ẩn chứa khí tức không cảnh, sát lục nguyên vẹn cả đời Thanh Thủy cùng hồn lực, nếu Vương Lâm luyện hóa cảm ngộ được thì sẽ có sát lục bổn nguyên. Là pháp bảo bổn nguyên đầu tiên của tu sĩ bước thứ ba, ngay cả lão tổ Hỏa Tước tộc, Nam Chiếu Thượng Nhân, Thiên Triệu Thượng Sư, Linh Động Thượng Nhân, Hồng Sam Tử, Nam Vân Tử đều không làm nổi.","hinhDang":"Hắc kiếm","nguonGoc":"Thanh Thủy ngưng tụ từ sát lục bổn nguyên khi phá không môn","congNang":["Chứa sát lục bổn nguyên đầy đủ — luyện hóa cảm ngộ sẽ có sát lục bổn nguyên @c1467","Chứa khí tức không cảnh, sát lục cả đời Thanh Thủy và hồn lực @c1467","Chứa toàn bộ hồn phách người bị Thanh Thủy giết (trừ Hàm Yên) @c1467"],"uyLuc":"Đánh tan không môn, sát lục nồng đậm cực điểm cuốn động thiên địa.","dacDiem":"Pháp bảo bổn nguyên đầu tiên của tu sĩ bước thứ ba, cực kỳ hiếm — các đại năng hàng đầu đều không ngưng tụ nổi.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Thanh Thủy","tuChuong":"@c1467","denChuong":"@c1467","cachCoDuoc":"Tự ngưng tụ từ sát lục bổn nguyên khi phá không môn","trangThai":"đã tặng"},{"ten":"Vương Lâm","tuChuong":"@c1467","denChuong":"","cachCoDuoc":"Thanh Thủy tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1467","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ và đổi chủ","phamCap":"Pháp bảo bổn nguyên bước thứ ba","text":"Thanh Thủy dùng sát lục bổn nguyên ngưng tụ thành hắc kiếm phá không môn. Thu hồn phách vào kiếm rồi tặng Vương Lâm, nói nếu luyện hóa cảm ngộ sẽ có sát lục bổn nguyên.","anchor":"kiếm này là ta vì phá không môn mà ngưng tụ lại"}]},"capNhatToi":"@c1467","nguon":["@c1467"]},{"id":"thoa-cai-toc-co-xua","name":"Thoa cài tóc cổ xưa","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Không rõ","soHuu":["Thanh Thủy"],"trangThai":"Cài lên đầu tàn hồn Hàm Yên","blurb":"Di vật từ diệt giới mà Thanh Thủy mang theo, cài lên đầu tàn hồn thê tử Hàm Yên sau khi được Vương Lâm phong ấn.","detail":"Thoa cài tóc trông rất cổ xưa, là di vật từ diệt giới (sát lục giới). Thanh Thủy cài lên đầu tàn hồn Hàm Yên sau khi Vương Lâm dùng Cổ Tức Diệp và máu tiên nhân phong ấn tàn hồn nàng.","nguonGoc":"Di vật từ diệt giới (sát lục giới)","chuSoHuu":[{"ten":"Thanh Thủy","tuChuong":"@c1467","denChuong":"","cachCoDuoc":"Mang từ diệt giới","trangThai":"cài lên đầu tàn hồn Hàm Yên"}],"tabs":{"tienTrinh":[{"chuong":"@c1467","loai":"dùng","importance":"normal","giaiDoan":"Cài lên đầu tàn hồn Hàm Yên","text":"Thanh Thủy cài thoa cổ xưa (di vật diệt giới) lên đầu tàn hồn Hàm Yên sau khi được Vương Lâm phong ấn.","anchor":"xuất ra một cái thoa cài tóc trông rất cổ xưa"}]},"capNhatToi":"@c1467","nguon":["@c1467"]},{"id":"dao-qua-thu-ba","name":"Đạo quả thứ ba","category":"khac","categoryLabel":"Đạo quả","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đạo quả thứ ba là một đạo quả mơ hồ trong suốt treo dưới tầng mây ngũ sắc trong Thất Thải Giới, do chưởng tôn giới ngoại bố trí. Bên trong chứa vô số sợi tơ hấp thu dưỡng chất luyện hóa người bị giam, có khả năng phản chấn công kích thông thường. Vương Lâm đã cứu Hồng Sam Tử khỏi đạo quả, dùng huyết kiếm chặt cành cây thu lấy và tuyên bố sẽ nuốt hấp thu toàn bộ.","detail":"Đạo quả thứ ba là một trong những đạo quả được chưởng tôn giới ngoại bố trí bên trong Thất Thải Giới, treo mơ hồ trong suốt dưới tầng mây ngũ sắc. Điện chủ Thiên Phạt Điện khẳng định đạo quả do chưởng tôn bố trí, không ai phá được. Bên trong đạo quả có vô số sợi tơ nối với người bị giam — trong trường hợp này là Hồng Sam Tử — liên tục hấp thu dưỡng chất luyện hóa nạn nhân thành con rối giới ngoại. Người không sở hữu Thiên Nghịch sẽ bị luyện hóa đến chết. Khi bị công kích thông thường, đạo quả tự động phản chấn, đồng thời sợi tơ bên trong truyền lực gây thống khổ cực độ cho người bị giam. Tuy nhiên, Vương Lâm dùng tay phải phát ánh sáng nhu hòa xuyên vào đạo quả mà không hề bị phản chấn, cứu được Hồng Sam Tử, sau đó dùng huyết kiếm chặt cành cây thu lấy đạo quả, tuyên bố sẽ nuốt hấp thu toà","hinhDang":"Mơ hồ trong suốt, treo trên cành cây dưới tầng mây ngũ sắc","dacDiem":"Phản chấn khi bị công kích thông thường, sợi tơ bên trong hấp thu dưỡng chất luyện hóa người bị giam; người không có Thiên Nghịch sẽ bị luyện hóa đến chết","congNang":["Giam giữ sinh linh bên trong, dùng vô số sợi tơ hấp thu dưỡng chất luyện hóa nạn nhân thành con rối giới ngoại @c1469","Phản chấn tự động khi bị công kích thông thường; sợi tơ bên trong đồng thời truyền lực gây thống khổ cho người bị giam @c1469"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1469","denChuong":"","cachCoDuoc":"Dùng huyết kiếm chặt cành cây lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1469","loai":"doi-chu","importance":"major","giaiDoan":"Vương Lâm thu đạo quả","text":"Vương Lâm cứu Hồng Sam Tử khỏi đạo quả, dùng huyết kiếm chặt cành cây lấy đạo quả, tuyên bố sẽ nuốt hấp thu toàn bộ.","anchor":"Ta nuốt đạo quả này, có thể hấp thu toàn bộ"}]},"capNhatToi":"@c1469","nguon":["@c1469"]},{"id":"hat-giong-loi-hoa-bon-nguyen","name":"Hạt giống lôi hỏa bổn nguyên","cn":null,"category":"khac","categoryLabel":"Vật chí bảo","phamCap":"Chí bảo trong thiên địa","soHuu":["Thập Tam"],"trangThai":"Đã gieo vào hồn phách Thập Tam","blurb":"Hạt giống lôi hỏa bổn nguyên là tinh hoa cảm ngộ đại thành về lôi và hỏa bổn nguyên của Vương Lâm, được ngưng tụ thành hạt giống màu vàng chứa tiên lực huyết mạch và khí tức bước thứ ba. Vương Lâm dùng một chưởng gieo hạt giống này sâu vào hồn phách Thập Tam, truyền lại toàn bộ cảm ngộ lôi hỏa bổn nguyên bước thứ ba cho người nhận.","detail":"Hạt giống lôi hỏa bổn nguyên không phải pháp bảo thông thường mà là tinh hoa cảm ngộ được ngưng kết. Vương Lâm sau khi đạt đại thành cảm ngộ về lôi và hỏa bổn nguyên, dùng một chưởng ngưng tụ toàn bộ cảm ngộ đó thành một hạt giống màu vàng, bên trong hàm chứa tiên lực huyết mạch cùng khí tức thuộc bước thứ ba. Hạt giống được gieo sâu vào hồn phách Thập Tam, giúp người nhận tiếp thu trọn vẹn cảm ngộ lôi hỏa bổn nguyên bước thứ ba. Mức trân quý của hạt giống này đủ để gây tranh đoạt trong thiên địa.","congNang":["Truyền cảm ngộ lôi hỏa bổn nguyên bước thứ ba cho người nhận thông qua gieo vào hồn phách @c1472"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1472","denChuong":"@c1472","cachCoDuoc":"Tự ngưng tụ từ cảm ngộ","trangThai":"Đã trao"},{"ten":"Thập Tam","tuChuong":"@c1472","denChuong":"","cachCoDuoc":"Sư phụ Vương Lâm ban tặng","trangThai":"Đang sở hữu (gieo trong hồn phách)"}],"tabs":{"tienTrinh":[{"chuong":"@c1472","loai":"xuất hiện","importance":"major","giaiDoan":"Tạo ra và trao tặng","text":"Vương Lâm hóa cảm ngộ đại thành về lôi hỏa thành hạt giống màu vàng chứa tiên lực huyết mạch, dùng một chưởng gieo sâu vào hồn phách Thập Tam. Nói chỉ cho hạt giống bổn nguyên này, không cho pháp bảo.","anchor":"Hạt giống màu vàng này ẩn chứa những cảm ngộ đại thành của Vương Lâm đối với lôi và hỏa, đây là khí tức thuộc về bước thứ ba"}]},"nguon":["@c1472"],"dacDiem":"Không phải pháp bảo mà là tinh hoa cảm ngộ được ngưng kết; có màu vàng, chứa tiên lực huyết mạch và khí tức bước thứ ba; mức trân quý đủ gây tranh đoạt trong thiên địa."},{"id":"mau-tuoi-nguoi-dien","name":"Máu tươi người điên","cn":null,"category":"khac","categoryLabel":"Vật phẩm quý","phamCap":"Không rõ","soHuu":["Hứa Lập Quốc"],"trangThai":"Đã thu thập một phần","blurb":"Máu tươi của người điên, được chính hắn nói là rất quý giá. Hứa Lập Quốc và Lưu Kim Bưu dùng kế lừa để thu lấy.","detail":"Người điên tự cắn tay cho máu chảy tặng Hứa Lập Quốc và Lưu Kim Bưu để đổi lấy việc dẫn đi gặp nữ tử. Hứa Lập Quốc vẻ mặt hưng phấn cẩn thận hứng lấy, Lưu Kim Bưu cũng hai mắt sáng ngời thèm muốn. Nguồn gốc giá trị chưa được tiết lộ.","nguon":["@c1472"]},{"id":"giot-mau-mau-vang","name":"Giọt máu màu vàng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được thu thập","blurb":"Giọt máu màu vàng được Hứa Lập Quốc và Lưu Kim Bưu thu thập, sau bị Vương Lâm lấy lại hơn phân nửa.","detail":"Những giọt máu có màu vàng, được Hứa Lập Quốc thu thập tại vùng này với lý do vì chủ nhân (Vương Lâm). Nguồn gốc và công dụng cụ thể chưa rõ. Vương Lâm lấy lại hơn phân nửa sau khi trừng phạt hai nô bộc.","chuSoHuu":[{"ten":"Hứa Lập Quốc","tuChuong":"@c1474","denChuong":"@c1474","cachCoDuoc":"Thu thập","trangThai":"bị thu hồi"},{"ten":"Lưu Kim Bưu","tuChuong":"@c1474","denChuong":"@c1474","cachCoDuoc":"Thu thập","trangThai":"bị thu hồi"},{"ten":"Vương Lâm","tuChuong":"@c1474","denChuong":"","cachCoDuoc":"Lấy lại từ nô bộc","trangThai":"đang sở hữu"}],"congNang":["Chưa rõ công dụng cụ thể"],"tabs":{"tienTrinh":[{"chuong":"@c1474","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm thu hồi","text":"Hứa Lập Quốc và Lưu Kim Bưu thu thập được giọt máu vàng, bị Vương Lâm lấy lại hơn phân nửa sau khi trừng phạt hai người.","anchor":"những giọt máu màu vàng mà họ lấy được cũng đã bị Vương Lâm lấy lại hơn phân nửa"}]},"nguon":["@c1474"]},{"id":"mat-trai-dao-co-diep-mich","name":"Mắt trái Đạo Cổ Diệp Mịch","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Không rõ","soHuu":["Đạo Cổ Diệp Mịch"],"trangThai":"Bị phong ấn tại tầng 19 hố sâu Phù Văn tộc","blurb":"Mắt trái của Đạo Cổ Diệp Mịch, bị Lý Quảng bắn rơi bằng mũi tên mang huyết mạch tiên nhân. Chứa cả khí tức Đạo Cổ lẫn huyết mạch tiên nhân, hai lực bài xích nhau được Phù Văn tộc biến thành phong ấn cực mạnh ngang Thiên Nhân đệ ngũ suy, cất giấu tại tầng 19 hố sâu Phù Văn tộc trên Chu Tước Tinh.","detail":"Năm xưa Lý Quảng bắn mũi tên vào mắt trái Đạo Cổ Diệp Mịch khiến nó rơi rụng tiêu tán trong tinh không. Mũi tên dính máu huyết Lý Quảng nên mắt trái mang cả khí tức Đạo Cổ lẫn khí tức huyết mạch tiên nhân. Hai luồng lực lượng bài xích lẫn nhau, Phù Văn tộc đã dùng thủ đoạn biến lực bài xích này thành một đạo phong ấn, cất giấu mắt trái tại tầng 19 hố sâu của mình trên Chu Tước Tinh, che giấu bí mật khỏi cả thiên hạ. Vương Lâm phá ngọn lửa bổn nguyên ở tầng 18, lộ ra cánh cửa tầng 19 với phong ấn dày đặc phù văn, rồi phá gần hết phong ấn và cảm nhận khí tức Đạo Cổ Diệp Mịch từ ký hiệu cuối cùng, từ đó suy đoán ra chân tướng. @c1479","congNang":["Chứa khí tức Đạo Cổ và huyết mạch tiên nhân, hai lực bài xích nhau tạo thành phong ấn cực mạnh ngang Thiên Nhân đệ ngũ suy @c1479"],"tabs":{"tienTrinh":[{"chuong":"@c1479","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phong ấn tại tầng 19","text":"Vương Lâm phá ngọn lửa bổn nguyên tầng 18, lộ cánh cửa tầng 19 với phong ấn dày đặc phù văn. Phá hết phong ấn chỉ còn ký hiệu cuối cùng — vòng tròn chứa uy áp huyết mạch tiên nhân lẫn khí tức Đạo Cổ. Suy đoán vật bị phong ấn chính là mắt trái Đạo Cổ Diệp Mịch.","anchor":"mắt trái của Đạo Cổ Diệp Mịch không ngờ ở nơi này"}]},"nguon":["@c1479"]},{"id":"mui-ten-ly-quang","name":"Mũi tên Lý Quảng","cn":"","aliases":["Mũi tên khổng lồ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Quảng"],"trangThai":"phong-an","blurb":"Mũi tên dài mấy vạn trượng do Lý Quảng bắn ra trong vùng đất cổ mộ, mang thần thông Đạo cổ vô biên, từng bắn rơi mắt trái Đạo cổ Diệp Mịch. Đầu mũi tên hình tròn là một ấn ký, trên đầu còn vết máu khô đen từ mắt trái Đạo cổ chứa yêu khí cực đậm và lực bài xích do dung hợp tiên-cổ.","detail":"Mũi tên do Lý Quảng dùng cung bắn ra trong trận chiến tại vùng đất cổ mộ, mang theo thần thông Đạo cổ vô biên và sức mạnh thân thể Lý Quảng. Mũi tên bắn rơi mắt trái Đạo cổ Diệp Mịch, mang mắt trái bay ra khỏi cổ mộ xuyên thấu tinh không, phá tan mấy tu chân tinh trên đường đi. Trong khi bay, mắt trái tách khỏi mũi tên rơi vào tinh hải. Mũi tên dư lực hết dần, bay vào một thiên địa ẩn giấu, phá tan bầu trời tạo lỗ thủng rộng mấy ngàn trượng rồi mắc kẹt tại đó. Sát khí còn sót trên mũi tên cùng máu mắt trái Đạo cổ dung hợp tiên-cổ, tạo ra sức mạnh kinh thiên, phóng ra cơn lốc hủy diệt toàn bộ thiên địa ấy. Đầu mũi tên không nhọn mà có hình tròn, thực chất là một ấn ký có khả năng hấp thụ lực bài xích, tạo thành các vòng tròn từ to đến nhỏ lan xuống mặt đất, xuyên sâu vào lòng đất hình thành","hinhDang":"Dài mấy vạn trượng, đầu hình tròn là ấn ký, không nhọn","nguonGoc":"Do Lý Quảng bắn ra trong vùng đất cổ mộ","uyLuc":"Bắn rơi mắt trái Đạo cổ Diệp Mịch, phá tan mấy tu chân tinh trên đường bay, sau khi mắc kẹt vẫn phóng ra cơn lốc dung hợp tiên-cổ hủy diệt toàn bộ một thiên địa.","dacDiem":"Dài mấy vạn trượng, đầu mũi tên không nhọn mà có hình tròn là một ấn ký. Trên đầu mũi tên có vết máu khô đen từ mắt trái Đạo cổ Diệp Mịch, ẩn chứa yêu khí cực đậm và lực bài xích do dung hợp tiên-cổ.","congNang":["Uy lực phá tinh không, xuyên thấu bầu trời, phá tan tu chân tinh trên đường bay @c1481","Sát khí và máu mắt trái Đạo cổ dung hợp tiên-cổ tạo lực bài xích kinh thiên, phóng cơn lốc hủy diệt nguyên một thiên địa @c1481","Ấn ký hình tròn ở đầu mũi tên hấp thụ lực bài xích, tạo các vòng tròn xuyên sâu vào lòng đất hình thành thông đạo @c1481","Tiên lực đặc biệt che giấu thiên địa nơi mũi tên mắc kẹt, khiến không ai tìm được @c1481"],"chuSoHuu":[{"ten":"Lý Quảng","tuChuong":"@c1481","denChuong":"","cachCoDuoc":"Tự bắn ra","trangThai":"da-ban"}],"capNhatToi":"@c1481","tabs":{"tienTrinh":[{"chuong":"@c1481","loai":"xuat-hien","importance":"major","giaiDoan":"Hé lộ toàn bộ lai lịch và Vương Lâm bắt đầu hấp thụ","text":"Vương Lâm phát hiện mũi tên dài mấy vạn trượng xuyên thấu bầu trời trong thiên địa ẩn giấu. Ghép nối toàn bộ lai lịch: Lý Quảng bắn rơi mắt trái Đạo cổ, mũi tên bay xuyên tinh không phá tu chân tinh rồi mắc kẹt ở đây, dung hợp tiên-cổ hủy diệt nguyên thiên địa. Phù Văn Tộc tìm được và phong ấn. Vương Lâm ngồi lên mũi tên dùng tinh điểm Cổ Thần hấp thụ vết máu mắt trái Đạo cổ chứa yêu khí cực đậm.","anchor":"mũi tên này rất lớn, rất lớn, uy lực ẩn chứa trên đó thậm chí có thể bắn rơi mắt trái của Đạo Cổ"}]},"nguon":["@c1481"]},{"id":"vet-mau-mat-trai-dao-co","name":"Vết máu mắt trái Đạo cổ","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-duoc-hap-thu","blurb":"Máu khô màu đen trên đầu mũi tên Lý Quảng, từ mắt trái Đạo cổ Diệp Mịch, chứa khí tức Đạo cổ và yêu khí cực đậm, là nguồn phát lực bài xích.","detail":"Vết máu khô màu đen dính trên đầu mũi tên Lý Quảng, là máu từ mắt trái Đạo cổ Diệp Mịch bị bắn rơi. Đây là nguồn phát ra khí tức Đạo cổ và lực bài xích trong thiên địa phong ấn. Ẩn chứa yêu khí cực đậm, rất có tác dụng với Vương Lâm. Vương Lâm dùng tinh điểm Cổ Thần trên mi tâm hấp thụ vết máu này.","congNang":["Chứa khí tức Đạo cổ và lực bài xích","Chứa yêu khí cực đậm, hữu ích cho tu luyện Cổ Thần"],"capNhatToi":"@c1481","tabs":{"tienTrinh":[{"chuong":"@c1481","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm bắt đầu hấp thụ","text":"Vương Lâm phát hiện vết máu khô đen trên đầu mũi tên là nguồn phát lực bài xích, dùng tinh điểm Cổ Thần hấp thụ yêu khí cực đậm bên trong.","anchor":"Trong vết máu này ẩn chứa một luồng yêu khí cực đậm"}]},"nguon":["@c1481"]},{"id":"pho-tuong-co-yeu","name":"Pho tượng cổ Yêu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Pho tượng cổ Yêu nằm ở tay trái Vương Lâm, mắt trái ngưng tụ các tinh điểm cổ Yêu lực. Đạt bảy tinh điểm sau khi hấp thu huyết dịch mắt trái Đạo cổ và yêu lực cổ Yêu từ Huyết Thần Tử, bộc phát yêu khí gào thét kinh thiên.","detail":"Mắt trái pho tượng ngưng tụ các tinh điểm yêu lực qua quá trình luyện hóa. Tinh điểm thứ sáu đạt được nhờ Vương Lâm luyện hóa huyết dịch mắt trái Đạo cổ trong mười ngày @c1482. Tinh điểm thứ bảy đạt được nhờ kết hợp dư lực huyết dịch Đạo cổ và yêu lực cổ Yêu lấy từ Huyết Thần Tử @c1482. Khi đạt bảy tinh điểm, yêu khí gào thét kinh thiên. Vương Lâm có cảm giác máu mủ tình thâm với pho tượng.","congNang":["Ngưng tụ tinh điểm cổ Yêu lực trong mắt trái, tích lũy yêu lực qua luyện hóa huyết dịch và hấp thu yêu lực cổ Yêu @c1482","Bộc phát yêu khí kinh thiên khi đạt bảy tinh điểm @c1482"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1482","denChuong":"","cachCoDuoc":"Sở hữu từ trước, nâng cấp tinh điểm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1482","loai":"nâng cấp","importance":"major","giaiDoan":"Đạt bảy tinh điểm","text":"Vương Lâm luyện hóa huyết dịch mắt trái Đạo cổ mười ngày, ngưng tụ tinh điểm thứ sáu. Phá phong ấn cổ Yêu Huyết Thần Tử, đập tan yêu tinh dồn yêu lực, ngưng tụ tinh điểm thứ bảy.","anchor":"trong mắt trái pho tượng cổ Yêu của Vương Lâm, tinh điểm thứ bảy đã ngưng tụ thành hình"}]},"nguon":["@c1482"],"uyLuc":"Đạt bảy tinh điểm, yêu khí gào thét kinh thiên @c1482"},{"id":"lau-cac-dia-phu-dao-co-diep-mich","name":"Lầu các địa phủ Đạo cổ Diệp Mịch","cn":"","aliases":["Lầu các màu đen","Hắc Tháp"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"cất giữ","blurb":"Địa phủ của Đạo cổ Diệp Mịch, bên trong phong ấn ba thần hồn cực kỳ hùng mạnh — kẻ địch mà Đạo cổ đã phong ấn ở cố hương năm đó.","detail":"Vương Lâm tìm được trong vùng đất Cổ Thần. Bên trong phong ấn ba thần hồn quá mức hùng mạnh, Vương Lâm cân nhắc dùng để gia tăng hai ký hiệu còn lại trên mũi tên Lý Quảng nhưng quyết định không thả vì thực lực hiện tại chưa đủ chống đỡ nếu bị đánh trả.","congNang":["Phong ấn ba thần hồn cực mạnh bên trong"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1482","denChuong":"","cachCoDuoc":"Tìm được trong vùng đất Cổ Thần","trangThai":"cất giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1482","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm lấy ra cân nhắc","text":"Vương Lâm lấy lầu các ra cân nhắc dùng ba thần hồn bên trong gia tăng hai ký hiệu còn lại trên mũi tên, nhưng quyết không thả vì nguy cơ bị đánh trả.","anchor":"Ba thần hồn này quá mức hùng mạnh, là kẻ địch mà Đạo cổ đã phong ấn ở cố hương năm đó"}]},"nguon":["@c1482"]},{"id":"han-kiem-nam-tu-ao-trang","name":"Hàn kiếm","cn":"","aliases":["Đoản kiếm lam"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam tử áo trắng"],"trangThai":"hong","blurb":"Đoản kiếm lam kèm trụ băng của nam tử áo trắng, xuyên thấu Quang Ảnh Thuẫn và cắt đứt Dịch Linh Ấn của Vương Lâm nhưng bị huyết kiếm đánh vỡ đôi.","detail":"Đoản kiếm toàn thân lam sắc phóng ra kiếm khí hàn băng kèm trụ băng, có thể đóng băng phòng ngự của đối thủ. Xuyên thấu Quang Ảnh Thuẫn và cắt đứt Dịch Linh Ấn trong một đòn, nhưng va chạm với huyết kiếm của Vương Lâm thì bị vỡ đôi.","congNang":["Phóng kiếm khí hàn băng kèm trụ băng","Đóng băng phòng ngự của đối thủ"],"nguon":["@c1484"]},{"id":"co-cam-tien-phi","name":"Cổ cầm (nữ tử tiên phi)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nữ tử tiên phi"],"trangThai":"da-huy","blurb":"Cổ cầm là pháp bảo do Tiên Tôn ban tặng cho nữ tử tiên phi Âm Nguyệt, có thể được biến ảo ra để gảy khúc Táng Hoàng Tuyền. Tiếng đàn hóa sát khí oanh kích tâm thần đối thủ, song cuối cùng bị dùng làm lá chắn trước mũi tên và vỡ tan thành vô số mảnh.","detail":"Cổ cầm là cây đàn do Tiên Tôn ban tặng cho Tiên Phi Âm Nguyệt. Khi chiến đấu, nữ tử tiên phi tay phải giơ lên vung về phía trước, biến ảo ra cây cổ cầm để gảy khúc Táng Hoàng Tuyền. Tiếng đàn phát ra hóa thành sát khí kinh động đất trời, oanh kích tâm thần đối thủ, tạo ma niệm. Tại mốc @c1487, cổ cầm được dùng tấn công tâm thần của Vương. Đến @c1490, trong tình thế nguy cấp, Tiên Phi Âm Nguyệt lấy cây đàn ra chắn mũi tên. Đàn vỡ tan thành vô số mảnh, không cản được đòn tấn công, đánh dấu sự hủy diệt của pháp bảo này.","congNang":["Phát tiếng đàn hóa sát khí kinh động đất trời, oanh kích tâm thần đối thủ, tạo ma niệm — dùng khi gảy khúc Táng Hoàng Tuyền @c1487","Phòng ngự — dùng làm lá chắn trước mũi tên, nhưng vỡ tan không cản được @c1490"],"chuSoHuu":[{"ten":"Nữ tử tiên phi","tuChuong":"@c1487","denChuong":"@c1490","cachCoDuoc":"Tiên Tôn ban tặng","trangThai":"da-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"xuat hien","importance":"normal","giaiDoan":"Biến ảo lần đầu","text":"Nữ tử tiên phi biến ảo ra cổ cầm để gảy khúc Táng Hoàng Tuyền, tiếng đàn hóa sát khí oanh kích tâm thần Vương Lâm.","anchor":"tay phải giơ lên vung về phía trước. Lập tức có một cây cổ cầm biến ảo ra"},{"chuong":"@c1490","loai":"dùng","importance":"major","giaiDoan":"Bị phá hủy","text":"Tiên Phi Âm Nguyệt lấy cây đàn do Tiên Tôn ban tặng ra chắn mũi tên. Đàn vỡ tan thành vô số mảnh, không cản được, mũi tên xuyên qua mi tâm giết chết nàng.","anchor":"cây đàn này liền ầm ầm vỡ tan, biến thành vô số mảnh bị cuốn đi"}]},"capNhatToi":"@c1487","nguon":["@c1487","@c1490"],"aliases":["Cây đàn của Tiên Phi Âm Nguyệt"],"uyLuc":"Tiếng đàn hóa sát khí kinh động đất trời, oanh kích tâm thần tạo ma niệm; tuy nhiên khi dùng chắn mũi tên thì vỡ tan thành vô số mảnh, không đủ sức cản.","dacDiem":"Cây đàn do Tiên Tôn ban tặng, có thể được biến ảo ra từ tay tiên phi; cuối cùng đã bị phá hủy hoàn toàn khi dùng làm lá chắn."},{"id":"vien-da-den-tien-phi-boi-toan","name":"Viên đá đen bảo hộ (Tiên Phi bói toán)","cn":"","aliases":["Dây chuyền viên đá đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ (Tiên Tôn ban tặng)","soHuu":["Nữ tử tử y"],"trangThai":"hu-ton","blurb":"Viên đá đen hình tròn đeo trên dây chuyền trên cổ Tiên Phi bói toán, do Tiên Tôn ban tặng. Tự động kích hoạt phát ánh sáng bảy màu bảo vệ chủ nhân khi gặp nguy hiểm chí mạng, đã cản được mũi tên của Lý Quảng nhưng xuất hiện vết nứt sau khi chịu lực.","detail":"Viên đá đen hình tròn treo trên sợi dây chuyền, do Tiên Tôn tặng cho Tiên Phi bói toán với mục đích bảo hộ nàng. Khi mũi tên xuyên qua mi tâm Tiên Phi bói toán, viên đá tự động phát ra ánh sáng bảy màu bao phủ toàn thân, giúp nàng không bị thương tổn. Tuy nhiên sau khi chịu đòn tấn công, viên đá xuất hiện vết nứt, cho thấy sức bảo hộ của nó có giới hạn và không thể chống đỡ vô hạn.","congNang":["Tự động kích hoạt bảo hộ chủ nhân khỏi tử vong khi gặp nguy hiểm chí mạng, phát ánh sáng bảy màu bao phủ toàn thân @c1490"],"chuSoHuu":[{"ten":"Nữ tử tử y","tuChuong":"@c1490","denChuong":"","cachCoDuoc":"Tiên Tôn ban tặng","trangThai":"hu-ton"}],"tabs":{"tienTrinh":[{"chuong":"@c1490","loai":"dùng","importance":"major","giaiDoan":"Kích hoạt bảo hộ, bị nứt","text":"Mũi tên xuyên qua mi tâm Tiên Phi bói toán nhưng viên đá đen tự động phát ánh sáng bảy màu bảo vệ toàn thân, nàng không bị thương. Viên đá xuất hiện vết nứt sau khi chịu đòn.","anchor":"nhưng lại không bị thương một chút nào, chỉ có hòn đá màu đen đang trôi lưng lửng kia trong tiếng rắc rắc đã xuất hiện một vết nứt"}]},"nguon":["@c1490"],"uyLuc":"Cản được mũi tên xuyên qua mi tâm, bảo toàn tính mạng chủ nhân hoàn toàn không bị thương tổn, nhưng viên đá xuất hiện vết nứt sau đó @c1490","dacDiem":"Hình tròn, màu đen, đeo trên sợi dây chuyền trên cổ; khi kích hoạt phát ánh sáng bảy màu; sức bảo hộ có giới hạn, xuất hiện vết nứt sau khi chịu lực"},{"id":"giot-mau-tien-nhan-bat-diet-the","name":"Giọt máu tiên nhân bất diệt thể","cn":"","category":"khac","categoryLabel":"Tinh hoa huyết mạch","phamCap":"Tiên nhân bất diệt thể","soHuu":[],"trangThai":"Lơ lửng chưa bị ai thu, Chưởng Tôn bị gián đoạn","blurb":"Giọt máu ngưng tụ từ toàn bộ huyết mạch tiên nhân và tủy sống bị tách khỏi cơ thể Vương Lâm, tỏa kim quang vạn trượng, chứa nửa ký hiệu tiên nhân bất diệt thể. Xuất hiện khi Chưởng Tôn dùng bổn nguyên thái sơ quy tắc cưỡng tách cơ duyên tiên nhân của Vương Lâm.","detail":"Huyết mạch tiên nhân và tủy sống vốn là cơ duyên mà người điên ban cho Vương Lâm, tồn tại bên trong cơ thể hắn. Tại chương @c1491, Chưởng Tôn sử dụng bổn nguyên thái sơ quy tắc tách hoàn toàn huyết mạch tiên nhân ra khỏi thân thể Vương Lâm. Huyết mạch thoát ra ngưng tụ thành thân ảnh kim quang, sau đó hóa thành một giọt máu tỏa kim quang vạn trượng. Giọt máu này chứa nửa ký hiệu tiên nhân bất diệt thể. Chưởng Tôn kích động muốn đoạt lấy nhưng bị Xích Hồn Tử gián đoạn.","congNang":["Chứa nửa ký hiệu tiên nhân bất diệt thể @c1491"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1491","denChuong":"@c1491","cachCoDuoc":"Bị tách khỏi cơ thể bởi Chưởng Tôn","trangThai":"mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1491","loai":"xuất hiện","importance":"major","giaiDoan":"Bị tách khỏi Vương Lâm","text":"Chưởng Tôn dùng bổn nguyên thái sơ quy tắc tách hoàn toàn huyết mạch tiên nhân khỏi Vương Lâm, ngưng tụ thành giọt máu tỏa kim quang vạn trượng chứa nửa ký hiệu tiên nhân bất diệt thể. Chưởng Tôn giơ tay định cầm nhưng bị Xích Hồn Tử gián đoạn.","anchor":"Ngay khi tách ra, thân ảnh kim quang này nhúc nhích, trong nháy mắt ngưng tụ lại hóa thành một giọt máu tỏa ra kim quang vạn trượng"}]},"nguon":["@c1491"],"dacDiem":"Toàn bộ huyết mạch tiên nhân và tủy sống ngưng tụ thành một giọt máu duy nhất, tỏa kim quang vạn trượng."},{"id":"huyet-dich-tien-nhan-bat-diet-the","name":"Huyết dịch tiên nhân bất diệt thể","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Huyết dịch màu vàng do huyết mạch tiên nhân ngưng tụ, tinh thuần tới cực điểm. Vương Lâm nắm lấy trước Chưởng Tôn và dự định luyện hóa thành pháp bảo tiên thể dung nhập cơ thể theo phương thức tránh bài xích.","detail":"Huyết dịch tiên nhân bất diệt thể là chất dịch màu vàng lơ lửng trên đỉnh đầu Vương Lâm, hình thành từ huyết mạch tiên nhân ngưng tụ mà thành, đạt tới mức tinh thuần cực điểm. Do bản chất đặc thù, huyết dịch này không thể thu vào khe trữ vật thông thường. Tại thời điểm xuất hiện (@c1492), Vương Lâm đã nắm lấy nó trước Chưởng Tôn và quyết định luyện hóa thành pháp bảo tiên thể, dung nhập trực tiếp vào cơ thể theo phương thức tránh bài xích.","dacDiem":"Huyết mạch tiên nhân ngưng tụ, tinh thuần cực điểm, không thể thu vào khe trữ vật","congNang":["Dự định luyện hóa thành pháp bảo tiên thể dung nhập cơ thể theo phương thức tránh bài xích @c1492"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1492","denChuong":"","cachCoDuoc":"Nắm lấy khi thoát giam cầm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1492","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm nắm giữ, dự định luyện thành pháp bảo","text":"Huyết dịch tiên nhân bất diệt thể lơ lửng trên đỉnh đầu Vương Lâm, được hắn nắm lấy trước Chưởng Tôn. Quyết định luyện hóa thành pháp bảo tiên thể dung nhập cơ thể thay vì dung hợp trực tiếp.","anchor":"Vương Lâm sẽ lựa chọn luyện hóa nó trở thành một kiện pháp bảo, một kiện pháp bảo tiên thể"}]},"nguon":["@c1492"]},{"id":"vien-dan-duoc-vo-tan-tinh-luc","name":"Viên đan dược vô tận tinh lực","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã dùng","blurb":"Viên đan dược Vương Lâm nuốt trước khi chu du, cung cấp vô tận tinh lực cho phàm thể suốt hành trình mười lăm năm.","detail":"Vương Lâm cất viên đan dược vào ngực rồi nuốt. Đan dược cho hắn vô tận tinh lực, nhiều khí lực hơn để hoàn thành tâm nguyện chu du các nước trên Chu Tước Tinh.","congNang":["Cung cấp vô tận tinh lực cho phàm thể @c1511"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1511","denChuong":"","cachCoDuoc":"Có từ trước, nuốt khi bắt đầu chu du","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1511","loai":"dùng","importance":"normal","giaiDoan":"Vương Lâm nuốt đan dược","text":"Vương Lâm nuốt viên đan dược, nhận vô tận tinh lực để chu du Chu Tước Tinh suốt mười lăm năm.","anchor":"Đan dược này cho hắn vô tận tinh lực, khiến cho Vương Lâm có nhiều khí lực hơn"}]},"nguon":["@c1511"]},{"id":"ngoc-gian-thanh-lam-tang","name":"Ngọc giản Thanh Lâm tặng Tư Đồ Nam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tư Đồ Nam"],"trangThai":"da-dung","blurb":"Pháp bảo được Thanh Lâm tặng cho Tư Đồ Nam, lóe kim quang hộ thể khẩn cấp, vỡ tan sau khi dùng một lần.","detail":"Ngọc giản pháp bảo do Thanh Lâm tặng. Khi kích hoạt, toàn thân chủ nhân lóe kim quang hộ thể. Vỡ tan sau khi dùng, chỉ dùng được một lần. Tư Đồ Nam kích hoạt trong lúc bị sương mù tím (Thái Cổ Ngũ Tôn) quét, phun máu nhưng thoát chết.","congNang":["Hộ thể khẩn cấp, lóe kim quang, vỡ tan khi dùng — dùng một lần"],"nguonGoc":"Thanh Lâm tặng cho Tư Đồ Nam","chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-tang"},{"ten":"Tư Đồ Nam","tuChuong":"","denChuong":"@c1521","cachCoDuoc":"Thanh Lâm tặng","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1521","loai":"dung","importance":"normal","giaiDoan":"Kích hoạt và vỡ tan","text":"Tư Đồ Nam trong lúc bị sương mù tím Thái Cổ Ngũ Tôn quét, kích hoạt ngọc giản, toàn thân lóe kim quang, ngọc giản vỡ tan, phun máu nhưng thoát chết.","anchor":"Toàn thân Tư Đồ Nam chợt lóe lên kim quang, trong lúc nguy cấp xuất ra pháp bảo được Thanh Lâm tặng"}]},"nguon":["@c1521"]},{"id":"giot-mau-bat-diet-the-tien-nhan","name":"Giọt máu bất diệt thể tiên nhân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sở hữu, chưa dung hợp","blurb":"Giọt máu màu vàng chứa toàn bộ bất diệt thể tiên nhân, vốn bị Chưởng Tôn tách khỏi thân thể Vương Lâm năm xưa. Huyết quang quanh thân hắn sụp đổ ngưng tụ thành giọt máu này, tỏa tiên khí kinh người, được Vương Lâm thu hồi và đặt lên mi tâm làm pháp bảo.","detail":"Bất diệt thể tiên nhân vốn thuộc về Vương Lâm, bị Chưởng Tôn tách khỏi thân thể hắn năm xưa. Tại chương 1522, huyết quang bao phủ quanh thân Vương Lâm sụp đổ, toàn bộ ngưng tụ lại thành một giọt máu màu vàng tỏa ra tiên khí kinh người — đó chính là toàn bộ bất diệt thể của tiên nhân. Vương Lâm đặt giọt máu lên mi tâm nhưng chưa dung hợp, tuyên bố sẽ dùng nó làm pháp bảo.","hinhDang":"Giọt máu màu vàng, tỏa tiên khí","nguonGoc":"Bất diệt thể tiên nhân vốn thuộc Vương Lâm, bị Chưởng Tôn tách khỏi thân thể năm xưa","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1522","denChuong":"","cachCoDuoc":"Thu hồi từ huyết quang quanh thân","trangThai":"dang-co"}],"congNang":["Chứa toàn bộ bất diệt thể tiên nhân @c1522","Tỏa tiên khí kinh người @c1522","Bị tiên khí Tiên Cương đại lục hấp dẫn"],"tabs":{"tienTrinh":[{"chuong":"@c1522","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm thu hồi","text":"Huyết quang quanh thân Vương Lâm sụp đổ ngưng tụ thành giọt máu bất diệt thể tiên nhân. Đặt lên mi tâm chưa dung hợp, định dùng làm pháp bảo.","anchor":"Thay vào đó là một giọt máu màu vàng tỏa ra tiên khí kinh người. Đây chính là toàn bộ bất diệt thể của tiên nhân"}]},"nguon":["@c1522"]},{"id":"bon-bao-vat-truyen-thua-tu-thanh-tong","name":"Bốn bảo vật truyền thừa Tứ Thánh Tông","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật truyền thừa","soHuu":["Thanh Long Thánh Hoàng"],"trangThai":"dang-co","blurb":"Bốn bảo vật truyền thừa của Tứ Thánh Tông, được Thanh Long Thánh Hoàng túm hư không triệu ra bên thân, dự định dùng để trợ giúp Vương Lâm mở Không Môn ở thời điểm mấu chốt.","detail":"Thanh Long Thánh Hoàng giơ tay túm hư không, bốn bảo vật truyền thừa Tứ Thánh Tông hiện ra bên cạnh thân thể hắn. Dự định dùng chúng để giúp Vương Lâm mở cánh cửa Không Môn sáu đạo bổn nguyên tới thời điểm mấu chốt. Công năng cụ thể chưa được triển khai.","congNang":["Hỗ trợ mở Không Môn (dự định, chưa triển khai)"],"chuSoHuu":[{"ten":"Thanh Long Thánh Hoàng","tuChuong":"@c1524","denChuong":"","cachCoDuoc":"Bảo vật truyền thừa Tứ Thánh Tông","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1524","loai":"xuất hiện","importance":"normal","giaiDoan":"Được triệu ra chuẩn bị trợ giúp Vương Lâm","text":"Thanh Long Thánh Hoàng túm hư không, bốn bảo vật truyền thừa Tứ Thánh Tông hiện ra bên thân, dự định dùng ở thời điểm mấu chốt để giúp Vương Lâm mở Không Môn.","anchor":"bốn bảo vật truyền thừa của Tứ Thánh Tông hiện ra bên cạnh thân thể hắn"}]},"capNhatToi":"@c1524","nguon":["@c1524"]},{"id":"khong-mon","name":"Không Môn","cn":"空门","category":"khac","categoryLabel":"Cửa / Di tích","phamCap":"Sáu đạo bổn nguyên dẫn động","soHuu":[],"trangThai":"dang-co","blurb":"Không Môn là cánh cửa khổng lồ được sáu đạo bổn nguyên dẫn động, hùng mạnh hơn vô số lần so với Không Môn mà Tư Đồ Nam từng mở năm xưa. Vương Lâm đánh một quyền lôi đình khiến nó chấn động, chậm rãi hé ra một chút.","detail":"Không Môn là cánh cửa vượt qua cảnh giới, cần sức mạnh bổn nguyên để khai mở. Phiên bản này được sáu đạo bổn nguyên dẫn động, quy mô khổng lồ và uy lực hùng mạnh hơn vô số lần so với Không Môn mà Tư Đồ Nam từng mở khi xưa. Tại mốc khai phong, Vương Lâm đánh một quyền lôi đình lên Không Môn, chấn động lan ra khiến mấy vạn tu sĩ bốn phía phun máu tươi, thân thể lảo đảo; bản thân Không Môn toàn thân rung chuyển, chậm rãi hé ra một chút.","dacDiem":"Sáu đạo bổn nguyên dẫn động, khổng lồ, hùng mạnh hơn vô số lần so với Không Môn Tư Đồ Nam từng mở","congNang":["Cửa vượt qua cảnh giới, cần sức mạnh bổn nguyên để mở @c1524"],"tabs":{"tienTrinh":[{"chuong":"@c1524","loai":"khai phong","importance":"major","giaiDoan":"Hé mở dưới một quyền lôi đình của Vương Lâm","phamCap":"Sáu đạo bổn nguyên","text":"Vương Lâm đánh một quyền lôi đình lên Không Môn sáu đạo bổn nguyên. Chấn động khiến mấy vạn tu sĩ phun máu, Không Môn chậm rãi hé ra một chút. Sau đó Vương Lâm dẫn động lôi đình tứ đại tinh vực để tiếp tục mở cửa.","anchor":"Không Môn khổng lồ kia toàn thân chấn động, dường như không thể chịu đựng nổi, chậm rãi hé ra một chút"}]},"capNhatToi":"@c1524","nguon":["@c1524"],"uyLuc":"Khi bị Vương Lâm đánh một quyền lôi đình, chấn động từ Không Môn lan ra khiến mấy vạn tu sĩ bốn phía phun máu tươi, thân thể lảo đảo, song cánh cửa chỉ chậm rãi hé ra một chút."},{"id":"van-khong-cot-mon","name":"Vạn Không Cốt Môn","cn":"万空骨门","category":"khac","categoryLabel":"Khác","phamCap":"Truyền thuyết","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vạn Không Cốt Môn là Không Môn thứ sáu, được dẫn ra khi Vương Lâm hấp thụ sát lục bổn nguyên đại thành. Cánh cửa bằng bạch cốt hình đầu lâu khổng lồ xuất hiện kèm tuyết hoa màu đỏ tràn ngập, gợn sóng lan ra khiến gần vạn tu sĩ già đi mà chết thành tro bụi.","detail":"Khi Vương Lâm hấp thụ sát lục bổn nguyên đại thành, Không Môn thứ sáu hiện ra dưới dạng một cánh cửa bằng bạch cốt, hình đầu lâu khổng lồ, kèm tuyết hoa màu đỏ tràn ngập (@c1526). Gợn sóng từ cửa lan ra làm tu sĩ xung quanh già yếu, gần một vạn người trực tiếp già đi mà chết thành tro bụi. Hư Thần Thiên Tôn và Nam Vân Tử nhận ra đây chính là Vạn Không Cốt Môn — một truyền thuyết có nguồn gốc từ quê hương Tiên Phi và quê hương Phong Tôn. Cửa này không thuộc về Phong Giới mà hiện ở quê hương của Phong Tôn. Theo lời Tiên Phi, người có thể dẫn động được cánh cửa này cực kỳ hiếm gặp; nếu không gặp tai họa thì nhất định sẽ thành Đại Tôn.","hinhDang":"Cánh cửa bằng bạch cốt, hình đầu lâu khổng lồ","uyLuc":"Gợn sóng từ cửa lan ra khiến gần vạn tu sĩ già đi mà chết thành tro bụi (@c1526).","dacDiem":"Cánh cửa bằng bạch cốt hình đầu lâu khổng lồ; khi xuất hiện kèm tuyết hoa màu đỏ tràn ngập. Không thuộc Phong Giới mà hiện ở quê hương Phong Tôn; là truyền thuyết từ quê hương Tiên Phi.","congNang":["Gợn sóng từ cửa lan ra làm sinh linh già yếu rồi chết thành tro bụi, gần vạn tu sĩ bị diệt chỉ trong một lần xuất hiện (@c1526)","Là dấu hiệu cho thấy người dẫn động nếu không gặp tai họa nhất định thành Đại Tôn (@c1526)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1526","denChuong":"","cachCoDuoc":"Tự dẫn động bằng sát lục bổn nguyên (đạo thứ sáu)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1526","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm hấp thụ sát lục bổn nguyên đại thành, dẫn ra Không Môn thứ sáu — Vạn Không Cốt Môn bằng bạch cốt hình đầu lâu. Gợn sóng từ cửa giết gần vạn tu sĩ. Hư Thần Thiên Tôn và Nam Vân Tử nhận ra truyền thuyết.","anchor":"trực tiếp già đi mà chết, trở thành những đám tro bụi tiêu tan"}]},"nguon":["@c1526"]},{"id":"truong-thuong-suong-tim","name":"Trường thương sương tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hư Thần Thiên Tôn"],"trangThai":"dang-dung","blurb":"Vũ khí của Hư Thần Thiên Tôn, hóa từ đám sương mù màu tím trong tay thành trường thương mang sương mù vô tận.","detail":"Từ đám sương mù màu tím hiện ra trong tay Hư Thần Thiên Tôn, hóa thành trường thương mang sương mù vô tận vung thẳng tới Vương Lâm đang bị vây khốn.","chuSoHuu":[{"ten":"Hư Thần Thiên Tôn","tuChuong":"@c1528","denChuong":"","cachCoDuoc":"Tự hóa từ sương mù tím","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1528","loai":"dùng","importance":"normal","giaiDoan":"Hư Thần Thiên Tôn dùng vây khốn Vương Lâm","text":"Hư Thần Thiên Tôn hóa sương mù tím thành trường thương vung thẳng tới Vương Lâm đang bị vạn pho tượng và vòng xoáy vây khốn.","anchor":"liền có một đám sương mù màu tím hiện ra"}]},"nguon":["@c1528"]},{"id":"cung-ly-quang","name":"Cung Lý Quảng","cn":"李广弓","aliases":["Cây cung của Lý Quảng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cấp cực cao)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cung Lý Quảng là cây cung cổ đại ẩn chứa cùng mũi tên bên trong giọt máu vàng trên mi tâm Vương Lâm, được triệu hồi thông qua cảm ứng huyết mạch tiên nhân. Một tiễn bắn ra có thể dẫn động uy lực thiên địa, khiến tinh không sụp đổ, diệt tu sĩ Không Huyền và phân thân Hư Thần Thiên Tôn.","detail":"Cung Lý Quảng cùng mũi tên dung hợp bên trong giọt máu vàng sau khi huyết mạch tiên nhân của Vương Lâm bị bức ra. Vương Lâm dựa vào cảm ứng với giọt máu trên mi tâm để triệu hồi cung. Khi kéo cung bắn, mũi tên thực chất hóa, tinh không sụp đổ, dẫn động uy lực thiên địa. Gợn sóng từ đầu mũi tên lan khắp Côn Hư, bỏ qua tu sĩ giới nội nhưng khiến mọi tu sĩ giới ngoại chạm phải đều tan vỡ. Tại chương @c1529, Vương Lâm triệu Cung Lý Quảng từ giọt máu vàng, bắn một tiễn nhắm vào Hư Thần Thiên Tôn, diệt nam tử áo xanh — phân thân của y. Hư Thần Thiên Tôn từng nhận định rằng có cung tên này thì trong giới nội lẫn giới ngoại khó ai giết được Vương Lâm.","congNang":["Bắn một tiễn khiến tinh không sụp đổ, dẫn động uy lực thiên địa @c1529","Gợn sóng từ mũi tên phân biệt địch ta: bỏ qua tu sĩ giới nội, khiến mọi tu sĩ giới ngoại chạm phải đều tan vỡ, hiệu lực trên diện rộng","Xuyên diệt tu sĩ cảnh giới Không Huyền và phân thân Hư Thần Thiên Tôn @c1529"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1529","denChuong":"","cachCoDuoc":"Dung hợp trong giọt máu vàng từ huyết mạch tiên nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1529","loai":"dung","importance":"major","giaiDoan":"Tái xuất hiện — một tiễn quét sạch Côn Hư","text":"Vương Lâm triệu Cung Lý Quảng từ giọt máu vàng trên mi tâm. Bắn một tiễn nhắm Hư Thần Thiên Tôn, diệt nam tử áo xanh (tu sĩ Không Huyền đầu tiên tử vong), quét sạch tu sĩ giới ngoại khắp Côn Hư bằng gợn sóng, và xuyên diệt phân thân Hư Thần Thiên Tôn tại biên giới Vân Hải. Sau đó cung tên trở về giọt máu vàng, đặt lại mi tâm.","anchor":"Một tiễn này, ta muốn giành lại Côn Hư"}]},"nguon":["@c1529"],"uyLuc":"Một tiễn dẫn động uy lực thiên địa, tinh không sụp đổ, diệt phân thân Hư Thần Thiên Tôn; chính Hư Thần Thiên Tôn nhận định có cung tên này thì trong giới nội lẫn giới ngoại khó ai giết được Vương Lâm.","dacDiem":"Cung cùng mũi tên dung hợp bên trong giọt máu vàng trên mi tâm Vương Lâm, triệu hồi qua cảm ứng huyết mạch tiên nhân; khi bắn, mũi tên thực chất hóa và gợn sóng lan ra có khả năng tự phân biệt giới nội — giới ngoại."},{"id":"mui-ten-cung-ly-quang","name":"Mũi tên của Cung Lý Quảng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mũi tên đi kèm Cung Lý Quảng, từ hư ảo thực chất hóa trên dây cung, có thể truy sát mục tiêu và tạo gợn sóng diệt địch diện rộng.","detail":"Mũi tên đầu hình tròn từ hư ảo xuất hiện trên dây cung Lý Quảng, phá sụp tinh không khi bắn ra. Gợn sóng lan từ đầu mũi tên thành từng vòng khắp Côn Hư, không hại tu sĩ giới nội nhưng khiến mọi tu sĩ giới ngoại chạm phải đều tan vỡ. Mũi tên truy sát mục tiêu tới tận biên giới Côn Hư – Vân Hải, xuyên diệt phân thân Hư Thần Thiên Tôn, sau đó trở về giọt máu vàng.","congNang":["Xuyên sát mục tiêu, truy đuổi không ngừng","Tạo gợn sóng diệt địch diện rộng, phân biệt giới nội và giới ngoại"],"boCha":"cung-ly-quang","nguon":["@c1529"]},{"id":"loi-dinh-bon-nguyen-kiem","name":"Lôi đình bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Lôi đình bổn nguyên kiếm là thanh tiểu kiếm dài bảy tấc do Vương Lâm ngưng tụ từ lôi đình bổn nguyên nhờ sức mạnh Không Môn, là thanh đầu tiên trong bộ sáu bổn nguyên kiếm. Mỗi lần tấn công của kiếm mang toàn lực bước thứ ba toàn năng.","detail":"Lôi đình bổn nguyên kiếm được Vương Lâm ngưng tụ bên trong vòng xoáy Không Môn, lấy lôi đình bổn nguyên làm chất liệu cốt lõi. Thanh kiếm gần như chính là lôi đình bổn nguyên của Vương Lâm, bản chất tương tự sát lục kiếm mà Thanh Thủy năm đó từng sử dụng. Đây là thanh kiếm đầu tiên trong bộ sáu bổn nguyên kiếm, thuộc loại pháp khí bổn nguyên.","hinhDang":"Tiểu kiếm dài bảy tấc","nguonGoc":"Ngưng tụ từ lôi đình bổn nguyên nhờ sức mạnh Không Môn","uyLuc":"Mỗi lần tấn công là toàn lực bước thứ ba toàn năng.","congNang":["Pháp khí bổn nguyên, mỗi lần tấn công mang toàn lực bước thứ ba toàn năng @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"laBo":false,"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành trong vòng xoáy Không Môn","text":"Vương Lâm dùng sức mạnh Không Môn ngưng tụ thanh tiểu kiếm dài bảy tấc từ lôi đình bổn nguyên, pháp khí bổn nguyên đầu tiên.","anchor":"thanh tiểu kiếm dài bảy tấc này chính là do lôi đình bổn nguyên, đạo bổn nguyên thứ nhất của Vương Lâm ngưng tụ thành"}]},"nguon":["@c1530"]},{"id":"hoa-diem-bon-nguyen-kiem","name":"Hỏa diễm bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Hỏa diễm bổn nguyên kiếm là thanh kiếm thứ hai trong bộ sáu bổn nguyên kiếm của Vương Lâm, được ngưng tụ từ hỏa bổn nguyên nhờ sức mạnh Không Môn. Đây là pháp khí bổn nguyên có khả năng tấn công bằng toàn lực bước thứ ba.","detail":"Hỏa diễm bổn nguyên kiếm hình thành bên trong vòng xoáy Không Môn, khi lượng lớn Không Môn lực tiết ra đã ngưng tụ hỏa bổn nguyên của Vương Lâm thành hình dạng kiếm. Là thanh kiếm thứ hai trong bộ sáu bổn nguyên kiếm, mang thuộc tính hỏa, thuộc hệ thống pháp khí bổn nguyên.","nguonGoc":"Ngưng tụ từ hỏa bổn nguyên nhờ sức mạnh Không Môn","congNang":["Pháp khí bổn nguyên, tấn công bằng toàn lực bước thứ ba","Ngưng tụ từ hỏa bổn nguyên nhờ lượng lớn Không Môn lực @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành trong vòng xoáy Không Môn","text":"Thanh kiếm thứ hai ngưng tụ từ hỏa bổn nguyên nhờ lượng lớn Không Môn lực.","anchor":"Thanh kiếm thứ hai, chính là kiếm của hỏa bổn nguyên"}]},"nguon":["@c1530"]},{"id":"nhan-qua-bon-nguyen-kiem","name":"Nhân quả bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Nhân quả bổn nguyên kiếm là thanh kiếm thứ ba trong bộ sáu bổn nguyên kiếm của Vương Lâm, ngưng tụ từ nhân quả bổn nguyên nhờ sức mạnh Không Môn. Kiếm này dung hợp toàn bộ minh ngộ đối với nhân quả suốt cả đời Vương Lâm.","detail":"Nhân quả bổn nguyên kiếm là pháp khí bổn nguyên thứ ba được ngưng tụ từ nhân quả bổn nguyên nhờ sức mạnh Không Môn. Thanh kiếm lơ lửng trước người Vương Lâm trong vòng xoáy Không Môn, dung hợp toàn bộ sự minh ngộ của hắn đối với nhân quả tích lũy suốt đời, trở thành hiện thân của đại đạo nhân quả mà hắn đã lĩnh ngộ.","nguonGoc":"Ngưng tụ từ nhân quả bổn nguyên nhờ sức mạnh Không Môn","congNang":["Pháp khí bổn nguyên dung hợp toàn bộ minh ngộ nhân quả suốt đời Vương Lâm @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành trong vòng xoáy Không Môn","text":"Thanh kiếm thứ ba dung hợp minh ngộ nhân quả suốt đời Vương Lâm.","anchor":"Kiếm này dung hợp sự minh ngộ đối với nhân quả suốt cả đời Vương Lâm"}]},"nguon":["@c1530"]},{"id":"sinh-tu-bon-nguyen-kiem","name":"Sinh tử bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Sinh tử bổn nguyên kiếm là thanh kiếm thứ tư trong bộ sáu bổn nguyên kiếm, ngưng tụ từ sinh tử bổn nguyên nhờ sức mạnh Không Môn. Khi xuất hiện, thiên địa chấn động, hai luồng khí hắc bạch lượn lờ rồi hóa thành một đoản kiếm bên trong vòng xoáy Không Môn.","detail":"Sinh tử bổn nguyên kiếm là pháp khí bổn nguyên thứ tư, được ngưng tụ từ sinh tử bổn nguyên nhờ sức mạnh của Không Môn. Tại thời điểm xuất hiện (@c1530), thanh kiếm khiến thiên địa chấn động; hai luồng khí hắc bạch hiện ra rồi hóa thành hình dạng đoản kiếm bên trong vòng xoáy Không Môn. Là một trong bộ sáu bổn nguyên kiếm, Sinh tử bổn nguyên kiếm mang bản chất sinh tử, thể hiện qua sự giao hòa của hai luồng khí hắc bạch đối lập.","hinhDang":"Đoản kiếm","nguonGoc":"Ngưng tụ từ sinh tử bổn nguyên nhờ sức mạnh Không Môn","uyLuc":"Khi xuất hiện, thiên địa chấn động @c1530","congNang":["Pháp khí bổn nguyên, khi xuất hiện khiến thiên địa chấn động @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành trong vòng xoáy Không Môn","text":"Thanh kiếm thứ tư xuất hiện khiến thiên địa chấn động, hai luồng khí hắc bạch hóa thành đoản kiếm.","anchor":"Khi kiếm này xuất hiện, thiên địa chấn động, hai luồng khí hắc bạch lượn lờ"}]},"nguon":["@c1530"],"dacDiem":"Hai luồng khí hắc bạch lượn lờ rồi hóa thành đoản kiếm bên trong vòng xoáy Không Môn"},{"id":"chan-gia-bon-nguyen-kiem","name":"Chân giả bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Chân giả bổn nguyên kiếm là thanh kiếm thứ năm trong bộ sáu bổn nguyên kiếm của Vương Lâm, được ngưng tụ từ chân giả bổn nguyên nhờ sức mạnh Không Môn cưỡng đoạt từ vòng xoáy đang tiêu tán.","detail":"Trong quá trình tập hợp bộ bổn nguyên kiếm, Vương Lâm đã lợi dụng thời điểm vòng xoáy Không Môn đang tiêu tán để cưỡng ép kéo thêm sức mạnh từ đó, nhờ vậy ngưng tụ thành công thanh chân giả bổn nguyên kiếm. Đây là pháp khí bổn nguyên thứ năm, mang bản chất của chân giả bổn nguyên, được hình thành trong hoàn cảnh đặc biệt khi Vương Lâm chủ động cưỡng đoạt nguồn lực Không Môn.","nguonGoc":"Ngưng tụ từ chân giả bổn nguyên nhờ sức mạnh Không Môn cưỡng đoạt","congNang":["Pháp khí bổn nguyên, một trong sáu thanh bổn nguyên kiếm @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành khi vòng xoáy đang tiêu tán","text":"Vương Lâm cưỡng ép kéo thêm sức mạnh Không Môn để ngưng tụ chân giả kiếm.","anchor":"Dưới sức mạnh Không Môn vô biên này, chân giả kiếm bất ngờ ngưng tụ thành"}]},"nguon":["@c1530"]},{"id":"sat-luc-bon-nguyen-kiem-vuong-lam","name":"Sát lục bổn nguyên kiếm của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Sát lục bổn nguyên kiếm là thanh kiếm thứ sáu trong bộ sáu bổn nguyên kiếm, do chính Vương Lâm tự ngưng tụ từ sát lục bổn nguyên nhờ sức mạnh Không Môn, khác biệt hoàn toàn với thanh sát lục kiếm mà Thanh Thủy tặng. Sau khi thanh kiếm này thành hình, vòng xoáy Không Môn bắt đầu tan rã không thể cưỡng lại.","detail":"Đây là pháp khí bổn nguyên thứ sáu mà Vương Lâm sở hữu, nhưng khác với năm thanh trước, thanh kiếm này do chính Vương Lâm tự mình ngưng tụ từ sát lục bổn nguyên chứ không nhận từ người khác. Trong tiến trình tại chương @c1530, Vương Lâm dựa vào sức mạnh Không Môn để ngưng kết thành hình thanh kiếm này. Ngay khi thanh kiếm ngưng tụ hoàn tất, vòng xoáy Không Môn lập tức bắt đầu tan rã, cho thấy quá trình tạo kiếm đã tiêu hao toàn bộ lực lượng duy trì Không Môn.","dinhDanh":"dong-danh-khac-mon","nguonGoc":"Vương Lâm tự ngưng tụ từ sát lục bổn nguyên nhờ sức mạnh Không Môn","congNang":["Pháp khí bổn nguyên sát lục, do Vương Lâm tự ngưng tụ từ sát lục bổn nguyên nhờ sức mạnh Không Môn @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ bổn nguyên","trangThai":"dang-co"}],"boCha":"sau-bon-nguyen-kiem","tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành trong vòng xoáy Không Môn","text":"Thanh kiếm thứ sáu do Vương Lâm tự ngưng tụ từ sát lục bổn nguyên, không phải thanh kiếm Thanh Thủy tặng. Sau khi thành hình, vòng xoáy Không Môn tan rã.","anchor":"Kiếm này không phải là được Thanh Thủy tặng cho, mà là Vương Lâm tự mình ngưng tụ thành"}]},"nguon":["@c1530"]},{"id":"sau-bon-nguyen-kiem","name":"Sáu bổn nguyên kiếm","cn":"","category":"phap-bao","categoryLabel":"Bộ pháp khí bổn nguyên","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Bộ sáu thanh kiếm bổn nguyên do Vương Lâm ngưng tụ từ sáu đạo bổn nguyên nhờ sức mạnh Không Môn, mỗi lần tấn công là toàn lực bước thứ ba toàn năng.","detail":"Bộ gồm sáu thanh: lôi đình, hỏa diễm, nhân quả, sinh tử, chân giả và sát lục bổn nguyên kiếm. Tất cả đều là pháp khí do bổn nguyên của Vương Lâm biến thành, ngưng tụ trong vòng xoáy Không Môn. Mỗi lần tấn công đều mang toàn lực của bước thứ ba toàn năng.","laBo":true,"thanhVien":[{"id":"loi-dinh-bon-nguyen-kiem","vaiTro":"Kiếm thứ nhất — lôi đình"},{"id":"hoa-diem-bon-nguyen-kiem","vaiTro":"Kiếm thứ hai — hỏa diễm"},{"id":"nhan-qua-bon-nguyen-kiem","vaiTro":"Kiếm thứ ba — nhân quả"},{"id":"sinh-tu-bon-nguyen-kiem","vaiTro":"Kiếm thứ tư — sinh tử"},{"id":"chan-gia-bon-nguyen-kiem","vaiTro":"Kiếm thứ năm — chân giả"},{"id":"sat-luc-bon-nguyen-kiem-vuong-lam","vaiTro":"Kiếm thứ sáu — sát lục"}],"congNang":["Mỗi lần tấn công là toàn lực bước thứ ba toàn năng"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ sáu đạo bổn nguyên","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ cả bộ sáu kiếm trong vòng xoáy Không Môn","text":"Vương Lâm dùng sức mạnh Không Môn ngưng tụ lần lượt sáu thanh bổn nguyên kiếm tương ứng sáu đạo bổn nguyên của hắn.","anchor":"Đây là những pháp khí do bổn nguyên của Vương Lâm biến thành, mỗi một lần tấn công đều là toàn lực của bước thứ ba toàn năng"}]},"nguon":["@c1530"]},{"id":"giap-co-tay-co-than","name":"Giáp cổ tay Cổ Thần","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Mảnh giáp","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Giáp cổ tay của Cổ Thần, vốn bị vỡ thành mảnh, được Vương Lâm sở hữu và khôi phục về trạng thái hoàn chỉnh nhờ hấp thụ sức mạnh Không Môn tại chương @c1530.","detail":"Tấm giáp cổ tay này nguyên thuộc về Cổ Thần, sau bị vỡ thành mảnh. Vương Lâm thu được mảnh vỡ và mang nó vào vòng xoáy Không Môn. Tại đó, mảnh giáp hấp thụ sức mạnh Không Môn, từ trạng thái mảnh vỡ phục hồi hoàn chỉnh trở lại nguyên dạng ban đầu của nó.","nguonGoc":"Thuộc về Cổ Thần, Vương Lâm sở hữu mảnh vỡ","congNang":["Giáp phòng thủ cổ tay, nguyên bản thuộc trang bị của Cổ Thần","Có khả năng hấp thụ sức mạnh Không Môn để tự phục hồi từ trạng thái mảnh vỡ về hoàn chỉnh @c1530"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1530","denChuong":"","cachCoDuoc":"Khôi phục từ mảnh vỡ nhờ Không Môn lực","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"nâng cấp","importance":"major","giaiDoan":"Khôi phục hoàn chỉnh nhờ Không Môn lực","text":"Mảnh vỡ giáp cổ tay Cổ Thần hấp thụ sức mạnh Không Môn và trở lại trạng thái hoàn chỉnh như ban đầu.","anchor":"mảnh vỡ tấm giáp cổ tay của Cổ Thần được hắn lấy ra"}]},"nguon":["@c1530"]},{"id":"manh-giap-canh-tay-co-than","name":"Mảnh giáp bảo vệ cánh tay Cổ Thần","cn":"","category":"phap-bao","categoryLabel":"Giáp / Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"khôi phục","blurb":"Mảnh giáp bảo vệ cánh tay Cổ Thần của Vương Lâm, được sức mạnh Không Môn dung nhập và khôi phục lại như cũ.","detail":"Sau khi ý chí vòng xoáy Không Môn rút về, sức mạnh Không Môn kỳ dị dung nhập vào mảnh giáp bảo vệ cánh tay Cổ Thần, khiến mảnh giáp lập tức khôi phục lại như cũ.","congNang":["Bảo vệ cánh tay Cổ Thần"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1531","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1531","loai":"nhac-toi","importance":"normal","giaiDoan":"Khôi phục bởi sức mạnh Không Môn","text":"Sức mạnh Không Môn kỳ dị dung nhập vào mảnh giáp bảo vệ cánh tay Cổ Thần, khiến nó lập tức khôi phục lại như cũ.","anchor":"dung nhập vào trong mảnh giáp bảo vệ cánh tay Cổ Thần, khiến cho mảnh giáp này ngay lập tức khôi phục lại như cũ"}]},"nguon":["@c1531"]},{"id":"bon-kiem-te-dan-thien-kiep","name":"Bốn thanh kiếm quanh tế đàn thiên kiếp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Bốn thanh kiếm đặt quanh tế đàn trong cái khe thiên kiếp, từng khiến Vương Lâm kiêng kị. Bị Nhân Quả Ấn rút hết khí tức và linh khí, trở thành như sắt thường.","detail":"Bốn kiếm nằm quanh tế đàn thiên kiếp trong cái khe, từng là yếu tố đáng gờm khiến Vương Lâm phải dè chừng. Khi bị Nhân Quả Ấn rút bốn đạo khí tức, chúng mất hết ánh sáng và linh khí, trở thành bốn thanh sắt thường vô dụng.","nguon":["@c1533"],"tabs":{"tienTrinh":[{"chuong":"@c1533","loai":"hu-ton/tu-bo","importance":"normal","giaiDoan":"Bị phá hủy bởi Nhân Quả Ấn","text":"Bị Nhân Quả Ấn rút hết bốn đạo khí tức, mất ánh sáng và linh khí, trở thành sắt thường.","anchor":"bốn thanh kiếm năm đó đã khiến cho Vương Lâm có chút kiêng kị lập tức mất hết cả ánh sáng"}]}},{"id":"tam-thien-phat-tran","name":"Tam Thiên phất trần","cn":"三千拂尘","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo thiên kiếp (cực phẩm)","soHuu":[],"trangThai":"dang-co","blurb":"Phất trần cán gỗ tím với ba nghìn sợi tơ bạc, bay ra từ khe thiên kiếp, diễn hóa mọi thần thông trong ký ức Vương Lâm để phong ấn hắn.","detail":"Phất trần dài bảy thước, cán gỗ tím, ba nghìn sợi bạc tượng trưng ba nghìn đại đạo. Khi bay ra từ khe thiên kiếp, mỗi sợi tơ lần lượt hóa thành một thần thông mà Vương Lâm từng biết hoặc chứng kiến, mang tiên lực tinh thuần. Ba nghìn thần thông sau đó quấn chặt Vương Lâm như phong ấn bên trong Trấn Tiên bảo tháp. Chiến lão quỷ nhận ra đây là một trong ba pháp bảo được đưa vào thiên kiếp trong phủ.","hinhDang":"Cán gỗ tím, dài bảy thước, ba nghìn sợi tơ bạc","nguonGoc":"Được đưa vào thiên kiếp trong phủ bởi một nhân vật bí ẩn (theo lời Chiến lão quỷ)","congNang":["Diễn hóa ba nghìn thần thông từ ký ức mục tiêu @c1534","Quấn phong ấn mục tiêu bằng sợi tơ mang tiên lực @c1534"],"chuSoHuu":[],"dinhDanh":"goc","laBo":true,"thanhVien":[{"id":"tam-thien-phat-tran","vaiTro":"Bộ ba pháp bảo thiên kiếp — phất trần"},{"id":"tran-tien-bao-thap","vaiTro":"Bộ ba pháp bảo thiên kiếp — bảo tháp"},{"id":"phong-menh-hoan","vaiTro":"Bộ ba pháp bảo thiên kiếp — Phong Mệnh"}],"tabs":{"tienTrinh":[{"chuong":"@c1534","loai":"xuat-hien","importance":"major","giaiDoan":"Thiên kiếp bước thứ ba","text":"Bay ra từ khe thiên kiếp, ba nghìn sợi tơ bạc diễn hóa thành ba nghìn thần thông mang tiên lực công kích và phong ấn Vương Lâm. Chiến lão quỷ nhận ra đây là pháp bảo từng được đưa vào thiên kiếp trong phủ.","anchor":"ba nghìn sợi tơ ở bên ngoài cái khe, ở trước mặt Vương Lâm bất ngờ hóa thành ba nghìn loại thần thông"}]},"capNhatToi":"@c1534","nguon":["@c1534"]},{"id":"tran-tien-bao-thap","name":"Trấn Tiên bảo tháp","cn":"镇仙宝塔","aliases":["Trấn Tiên Tháp","Bảo tháp thiên kiếp","Bảo tháp chín tầng màu vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo thiên kiếp (cực phẩm)","soHuu":[],"trangThai":"dang-co","blurb":"Trấn Tiên bảo tháp là bảo tháp chín tầng toàn thân màu vàng, pháp bảo thứ hai trong bộ ba thiên kiếp trong phủ, bay ra từ khe thiên kiếp sau Tam Thiên phất trần và bành trướng cao mấy vạn trượng để trấn áp và luyện hóa Vương Lâm. Uy lực của tháp đủ uy hiếp tu sĩ Không Linh trung kỳ bình thường chỉ có một đạo bổn nguyên.","detail":"Trấn Tiên bảo tháp là bảo tháp chín tầng toàn thân màu vàng, được một nhân vật bí ẩn đưa vào thiên kiếp trong phủ theo lời Chiến lão quỷ nhận định. Đây là pháp bảo thứ hai trong bộ ba thiên kiếp trong phủ, xuất hiện sau Tam Thiên phất trần. Khi kích phát, tháp bay ra từ khe thiên kiếp và nhanh chóng bành trướng thành cao mấy vạn trượng, trấn áp xuống vị trí Vương Lâm đang bị ba nghìn thần thông che phủ. Bên trong tháp, hào quang vàng mang ý chí bá đạo kết hợp tiên lực để luyện hóa mục tiêu. Uy lực của tháp được đánh giá đủ giết tu sĩ Không Niết sơ kỳ, Không Niết đại viên mãn, thậm chí uy hiếp cả tu sĩ Không Linh trung kỳ bình thường chỉ có một đạo bổn nguyên.","hinhDang":"Bảo tháp chín tầng, toàn thân màu vàng","nguonGoc":"Được đưa vào thiên kiếp trong phủ bởi một nhân vật bí ẩn (theo lời Chiến lão quỷ)","congNang":["Trấn áp mục tiêu bằng trọng lực và uy áp thiên kiếp, bành trướng cao mấy vạn trượng đè xuống đối phương @c1534","Phóng hào quang vàng mang ý chí bá đạo kết hợp tiên lực để luyện hóa mục tiêu bên trong tháp @c1534"],"uyLuc":"Đủ giết tu sĩ Không Niết sơ kỳ, Không Niết đại viên mãn, thậm chí uy hiếp tu sĩ Không Linh trung kỳ bình thường chỉ có một đạo bổn nguyên.","chuSoHuu":[],"dinhDanh":"goc","boCha":"tam-thien-phat-tran","tabs":{"tienTrinh":[{"chuong":"@c1534","loai":"xuat-hien","importance":"major","giaiDoan":"Thiên kiếp bước thứ ba","text":"Bay ra từ khe thiên kiếp sau Tam Thiên phất trần, bành trướng cao mấy vạn trượng và trấn áp Vương Lâm. Bên trong tháp dùng hào quang vàng luyện hóa hắn bằng tiên lực nhưng Vương Lâm hóa thân Cổ Thần phản kích.","anchor":"Vật này là một tòa bảo tháp chín tầng, toàn thân có màu vàng"}]},"capNhatToi":"@c1534","nguon":["@c1534"],"dacDiem":"Bảo tháp chín tầng toàn thân màu vàng, pháp bảo thứ hai trong bộ ba thiên kiếp trong phủ, được một nhân vật bí ẩn đưa vào."},{"id":"phong-menh-hoan","name":"Phong Mệnh Hoàn","cn":"封命环","aliases":["Phong Mệnh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo thiên kiếp (chưa rõ chi tiết)","soHuu":[],"trangThai":"chua-xuat-hien","blurb":"Pháp bảo thứ ba trong bộ ba thiên kiếp, được Chiến lão quỷ nhắc tên nhưng chưa xuất hiện trực tiếp.","detail":"Chiến lão quỷ nhận ra ngoài Tam Thiên phất trần và Trấn Tiên bảo tháp, còn có một vật tên Phong Mệnh nằm trong bộ ba pháp bảo được đưa vào thiên kiếp trong phủ. Chương chưa mô tả hình dạng hay công năng.","nguonGoc":"Được đưa vào thiên kiếp trong phủ cùng Tam Thiên phất trần và Trấn Tiên bảo tháp","dinhDanh":"goc","boCha":"tam-thien-phat-tran","tabs":{"tienTrinh":[{"chuong":"@c1534","loai":"nhac-toi","importance":"normal","giaiDoan":"Thiên kiếp bước thứ ba — được Chiến lão quỷ nhắc tên","text":"Chiến lão quỷ nhắc tên Phong Mệnh là pháp bảo thứ ba trong bộ ba thiên kiếp trong phủ, chưa xuất hiện trực tiếp.","anchor":"hẳn là còn có một vật tên là Phong Mệnh nữa"}]},"capNhatToi":"@c1534","nguon":["@c1534"]},{"id":"bao-thap-thien-kiep","name":"Bảo tháp thiên kiếp","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo thiên kiếp","soHuu":[],"trangThai":"bi-pha-huy","blurb":"Bảo tháp thiên kiếp là pháp bảo dùng để phong ấn thân thể tu sĩ trong suốt thiên kiếp. Vương Lâm bị phong ấn bên trong bảo tháp này, nhưng đã dùng ba quyền mang uy thế đầu lâu Đạo Cổ phá nứt rồi đánh sụp nó hoàn toàn.","detail":"Bảo tháp thiên kiếp giam giữ Vương Lâm trong suốt thời gian thiên kiếp. Khi Vương Lâm tung ra ba quyền dung hợp uy thế đầu lâu Đạo Cổ, bảo tháp lần lượt nứt vỡ rồi sụp đổ hoàn toàn, giải phóng hắn khỏi phong ấn và mở đường cho pháp bảo thứ ba — Phong Mệnh Hoàn — xuất hiện.","congNang":["Phong ấn thân thể tu sĩ trong thiên kiếp @c1535"],"capNhatToi":"@c1535","tabs":{"tienTrinh":[{"chuong":"@c1535","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị Vương Lâm phá hủy","text":"Bảo tháp phong ấn Vương Lâm bị hắn dùng ba quyền mang uy thế Đạo Cổ phá nứt rồi sụp đổ hoàn toàn.","anchor":"bảo tháp này dưới ba quyền của Vương Lâm đã hoàn toàn sụp đổ"}]},"nguon":["@c1535"]},{"id":"quang-sang-mau-vang-tran-vuong-lam","name":"Quầng sáng màu vàng trên trán Vương Lâm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Quầng sáng màu vàng trên trán Vương Lâm là một bảo vật dạng quang giới, liên quan tới thiên kiếp. Sau khi giọt máu tiên nhân bất diệt thể bao phủ, kim quang chuyển hóa thành thuộc về chính Vương Lâm, được Chiến lão quỷ đánh giá là bảo vật đáng kích động vì được thu phục trong thời gian ngắn.","detail":"Trong quá trình Vương Lâm trải qua thiên kiếp, quầng sáng màu vàng trên trán hắn dần ảm đạm hoàn toàn. Khi đó, giọt máu vàng từ tiên nhân bất diệt thể bao phủ lên quầng sáng, khiến kim quang bộc phát và chuyển hóa, trở thành thuộc về chính Vương Lâm. Chiến lão quỷ nhận ra đây là bảo vật và tỏ ra kích động trước việc Vương Lâm thu phục được nó trong khoảng thời gian ngắn.","congNang":["Trong thiên kiếp, quầng sáng dần ảm đạm rồi được giọt máu tiên nhân bất diệt thể bao phủ, kim quang bộc phát chuyển hóa thuộc về Vương Lâm @c1536"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1536","denChuong":"","cachCoDuoc":"Thu phục trong thiên kiếp nhờ giọt máu tiên nhân bất diệt thể","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1536","loai":"xuat-hien","importance":"major","giaiDoan":"Thu phục trong thiên kiếp","text":"Quầng sáng trên trán dần ảm đạm, được giọt máu tiên nhân bất diệt thể bao phủ. Kim quang bộc phát thuộc về Vương Lâm, Chiến lão quỷ kích động gọi đây là bảo vật.","anchor":"Chẳng qua kim quang lần này là thuộc về Vương Lâm!"}]},"nguon":["@c1536"],"dacDiem":"Bảo vật dạng quang giới tồn tại trên trán Vương Lâm, liên quan tới thiên kiếp; được Chiến lão quỷ gọi là bảo vật và kích động vì Vương Lâm thu phục trong thời gian ngắn."},{"id":"chien-phu-co-ma","name":"Chiến phủ Cổ Ma","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Bốn Cổ Ma bát tinh trong thiên kiếp"],"trangThai":"da-huy","blurb":"Pháp khí do Cổ Ma biến ảo thành chiến phủ khổng lồ, bị Vương Lâm đặt chưởng lên lưỡi phủ làm tan nát thành ma khí.","detail":"Một trong bốn Cổ Ma biến ảo pháp khí thành chiến phủ khổng lồ chém Vương Lâm. Hắn đặt chưởng lên lưỡi phủ, làm nó tan nát thành ma khí rồi hấp thu vào mắt trái.","nguon":["@c1536"]},{"id":"tia-set-chin-mau-thien-kiep","name":"Tia sét chín màu (sấm sét thiên kiếp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (vật do đại tôn Tiên Cương ngưng tụ)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tia lôi đình chín màu bị phong ấn bên trong mặt trời thứ nhất ở Viễn cổ tiên vực, là căn nguyên dẫn dắt thiên kiếp thứ nhất — thiên lôi kiếp. Do nam tử trung niên đạo bào bảy màu (bổn tôn) ngưng tụ tạo ra nhằm trừng phạt nghịch tu.","detail":"Tia sét chín màu được phong ấn trong mặt trời thứ nhất tại Viễn cổ tiên vực. Vương Lâm phá vỡ mặt trời, giải phóng tia sét rồi nắm giữ trong tay. Tia sét không ngừng biến hóa, không ngừng giãy giụa, mang bản tính vĩnh viễn không chịu khuất phục trừ phi đối phương vượt qua chính người chế tạo ra nó. Vương Lâm đưa thần thức vào bên trong tia sét, nghịch chuyển thời gian, chứng kiến cảnh nam tử trung niên đạo bào bảy màu ngưng tụ tạo ra nó với mục đích làm sấm sét thiên kiếp để trừng phạt tu sĩ nghịch thiên. Chính tia sét chín màu này là căn nguyên dẫn dắt thiên kiếp thứ nhất trong tam đại thiên kiếp — thiên lôi kiếp.","congNang":["Là căn nguyên dẫn dắt thiên kiếp thứ nhất — thiên lôi kiếp @c1539"],"nguonGoc":"Do nam tử trung niên đạo bào bảy màu (bổn tôn) ngưng tụ tạo ra","dacDiem":"Chín màu, không ngừng biến hóa, mang bản tính vĩnh viễn không chịu khuất phục trừ phi đối phương vượt qua người chế tạo ra nó.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1539","denChuong":"","cachCoDuoc":"Phá mặt trời thứ nhất ở Viễn cổ tiên vực, giải phóng tia sét phong ấn bên trong","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1539","loai":"xuat-hien","importance":"major","giaiDoan":"Giải phóng từ mặt trời thứ nhất","text":"Vương Lâm phá mặt trời thứ nhất ở Viễn cổ tiên vực, giải phóng tia lôi đình chín màu bị phong ấn bên trong. Nhận ra đây là căn nguyên dẫn dắt thiên kiếp thứ nhất. Đưa thần thức vào tia sét, chứng kiến nam tử bảy màu tạo ra nó.","anchor":"Bởi có sự tồn tại của nó mà thiên kiếp đầu tiên thường thường là thiên lôi!"}]},"capNhatToi":"@c1539","nguon":["@c1539"]},{"id":"tinh-the-ky-uc-lao-gia-gay-go","name":"Tinh thể ký ức (lão già gầy gò)","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được giữ","blurb":"Tinh thể màu vàng nhạt to bằng nắm tay, chứa toàn bộ ký ức cả đời của lão già gầy gò — một sĩ tiên viễn cổ tiên vực. Lộ diện sau khi Vương Lâm phá vỡ phong ấn bảo vệ ký ức hạch tâm Thất Đạo Tông, được Vương Lâm đoạt giữ trước khi cơ chế tự huỷ kịp phá huỷ hoàn toàn.","detail":"Tinh thể ký ức này vốn bị phong ấn bên trong nam tử trung niên bảy màu — lớp phong ấn bảo vệ ký ức hạch tâm của Thất Đạo Tông. Tại chương @c1544, Vương Lâm dùng Cổ Tộc Bất Diệt Chỉ phá vỡ phong ấn, khiến tinh thể lộ ra. Phong ấn kích hoạt cơ chế tự huỷ làm tinh thể bắt đầu nứt vỡ, nhưng Vương Lâm kịp thời thi triển Định Thần Thuật đình chỉ quá trình huỷ diệt, sau đó dùng nguyên thần bao phủ đoạt lấy. Nội dung ký ức bên trong chưa được xem tại thời điểm này; được cho là chứa chân tướng về bản chất thiên địa. Tinh thể mang toàn bộ ký ức cả đời của lão già gầy gò, một sĩ tiên thuộc viễn cổ tiên vực.","congNang":["Chứa toàn bộ ký ức cả đời của lão già gầy gò (sĩ tiên viễn cổ tiên vực) @c1544"],"chuSoHuu":[{"ten":"Lão già khô gầy (sĩ tiên)","tuChuong":"@c1544","denChuong":"@c1544","cachCoDuoc":"Ngưng tụ từ ký ức trong thức hải","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1544","denChuong":"","cachCoDuoc":"Phá phong ấn tiên tôn, dùng Định Thần Thuật giữ lại rồi nguyên thần bao phủ đoạt","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1544","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện và đổi chủ","text":"Tinh thể lộ ra sau khi Vương Lâm phá phong ấn nam tử trung niên bảy màu. Sắp tự huỷ do cơ chế phong ấn nhưng bị Định Thần Thuật đình chỉ, Vương Lâm dùng nguyên thần bao phủ đoạt về.","anchor":"Tinh thể này chính là ký ức cả đời của lão già gầy gò này"}]},"nguon":["@c1544"],"dacDiem":"Tinh thể màu vàng nhạt to bằng nắm tay; có cơ chế tự huỷ gắn liền với phong ấn bảo vệ, khi phong ấn bị phá sẽ kích hoạt nứt vỡ tự huỷ nhằm ngăn nội dung ký ức lọt vào tay người ngoài."},{"id":"khai-thien-dao","name":"Khai thiên đao","cn":"开天刀","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bạch Hổ Thánh Hoàng"],"trangThai":"Bị phá hủy","blurb":"Khai Thiên Đao là vũ khí cận chiến của Bạch Hổ chiến tướng, xuất hiện trong trận đánh lén Vương Lâm tại @c1549. Thanh đao đã bị sáu chưởng ấn liên hoàn của Vương Lâm phá tan nát.","detail":"Khai Thiên Đao xuất hiện trên cánh tay phải của Bạch Hổ chiến tướng sau khi hư ảnh Bạch Hổ tiêu tán. Bạch Hổ cầm đao phối hợp cùng Thanh Long và Huyền Vũ đánh lén Vương Lâm @c1549. Tuy nhiên, Vương Lâm đáp trả bằng sáu chưởng ấn liên hoàn — gồm lửa chín màu, sấm sét, nhân quả bổn nguyện, sinh tử bổn nguyên, chân giả bổn nguyên và sát lục khí — khiến Khai Thiên Đao bị phá tan nát.","chuSoHuu":[{"ten":"Bạch Hổ Thánh Hoàng","tuChuong":"@c1549","denChuong":"@c1549","cachCoDuoc":"Vũ khí bản thân","trangThai":"Bị phá hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c1549","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị phá hủy","text":"Bạch Hổ chiến tướng cầm khai thiên đao chém Vương Lâm nhưng bị sáu chưởng ấn liên hoàn phá tan nát.","anchor":"thanh khai thiên đao trong tay Bạch Hổ chiến tướng chấn động mãnh liệt, trực tiếp tan nát"}]},"nguon":["@c1549"],"congNang":["Dùng làm vũ khí cận chiến của Bạch Hổ chiến tướng để chém đối thủ @c1549"]},{"id":"phap-bao-tien-nhan-ha-gioi","name":"Pháp bảo tiên nhân (giao cho người hạ giới)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên nhân cấp","soHuu":[],"trangThai":"da-dung","blurb":"Pháp bảo tiên nhân được tứ đại chiến tướng giao cho một người hạ giới, dung nhập vào đại trận hạ giới để chống giới ngoại 100 năm.","detail":"Tứ đại chiến tướng đưa cho một người hạ giới kêu gọi chống giới ngoại, dung nhập vào đại trận hạ giới. Tác dụng có hạn 100 năm, cần sức mạnh đại lục Tiên Cương hoặc tu sĩ hạ giới mới mở được.","congNang":["Tăng cường trận pháp phòng thủ hạ giới, chống cự giới ngoại 100 năm"],"nguon":["@c1550"],"tabs":{"tienTrinh":[{"chuong":"@c1550","loai":"nhắc tới","importance":"normal","giaiDoan":"Thanh Long tiết lộ nguồn gốc","text":"Thanh Long chiến tướng tiết lộ pháp bảo tiên nhân đã được giao cho người hạ giới dung nhập vào đại trận, chống cự 100 năm, đã qua hơn 90 năm.","anchor":"Chúng ta đã đưa cho hắn một loại pháp bảo của tiên nhân dung nhập vào trong một đại trận của hạ giới"}]}},{"id":"the-uoc-canh-lieu","name":"Tia thần thức hình cành liễu (thệ ước)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Thệ ước do Vương Lâm phân một tia thần thức ngưng tụ thành hình cành liễu, ràng buộc giao dịch với tứ đại chiến tướng.","detail":"Vương Lâm phân một tia thần thức từ mi tâm, ngưng tụ thành hình cành liễu dùng làm vật thệ ước. Đổi ý thì đạo mất người tan. Yêu cầu tứ đại chiến tướng cũng đưa đạo thệ thần thức tương tự.","congNang":["Thệ ước ràng buộc, vi phạm thì hủy đạo hủy người"],"nguon":["@c1550"],"tabs":{"tienTrinh":[{"chuong":"@c1550","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm tạo thệ ước giao dịch","text":"Vương Lâm phân tia thần thức ngưng tụ thành hình cành liễu làm thệ ước, yêu cầu tứ đại chiến tướng cũng đưa đạo thệ tương tự.","anchor":"Nếu đồng ý, thì hãy đưa ra đạo thệ do thần thức của các ngươi hóa thành"}]}},{"id":"con-roi-hac-quang-hong-sam-tu","name":"Con rối hắc quang (Hồng Sam Tử)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hồng Sam Tử"],"trangThai":"dang-co","blurb":"Hồng Sam Tử vung tay phóng một đạo hắc quang hóa thành con rối lao ra ngoài trận.","detail":"Hồng Sam Tử phóng ra một đạo hắc quang hóa thành con rối, lao thẳng ra ngoài tinh trận.","nguon":["@c1559"]},{"id":"gieng-huong-hoa-gioi-thu-hai","name":"Giếng khổng lồ (hương hỏa giới thứ hai của Chưởng Tôn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Hương hỏa giới thứ hai","soHuu":["Chưởng Tôn"],"trangThai":"dang-co","blurb":"Giếng khổng lồ là pháp bảo hương hỏa giới thứ hai của Chưởng Tôn, do người điên ở Tiên Cương đại lục ban cho. Bên trong ẩn chứa càn khôn nhật nguyệt, có khả năng phản chiếu và sao chép công kích của đối phương thành hư ảo để đối kháng.","detail":"Giếng khổng lồ là hương hỏa giới thứ hai trong số các pháp bảo của Chưởng Tôn, nguồn gốc từ người điên ở Tiên Cương đại lục ban tặng. Khi được triệu xuất trong lúc tuyệt vọng, giếng hiện ra với nội tại ẩn chứa càn khôn nhật nguyệt, tinh không vô tận. Mặt nước trong giếng có thể huyễn hóa, sao chép nguyên dạng công kích của đối phương để tạo ra hư ảo đối kháng. Tại trận chiến với Lý Quảng, Chưởng Tôn triệu giếng khổng lồ, mặt nước huyễn hóa ra mũi tên hư ảo giống hệt mũi tên của Lý Quảng nhằm chống đỡ, tuy nhiên hư ảo cuối cùng bị phá vỡ (@c1561).","congNang":["Phản chiếu và sao chép công kích của đối phương, huyễn hóa thành hư ảo giống hệt để đối kháng (@c1561)"],"nguonGoc":"Người điên ở Tiên Cương đại lục ban cho Chưởng Tôn","chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1561","denChuong":"","cachCoDuoc":"Được người điên ở Tiên Cương đại lục ban cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1561","loai":"dùng","importance":"major","giaiDoan":"Chưởng Tôn triệu xuất chống mũi tên Vương Lâm","text":"Chưởng Tôn triệu giếng khổng lồ, mặt nước huyễn hóa mũi tên hư ảo giống hệt mũi tên Lý Quảng để đối kháng, nhưng mũi tên hư ảo bị phá vỡ.","anchor":"Giếng này chính là hương hỏa giới thứ hai của Chưởng Tôn là pháp bảo mà hắn khi còn ở Tiên Cương đại lục được người điên ban cho"}]},"nguon":["@c1561"],"uyLuc":"Mặt nước giếng huyễn hóa ra mũi tên hư ảo giống hệt mũi tên của Lý Quảng để đối kháng, nhưng cuối cùng bị phá vỡ (@c1561).","dacDiem":"Bên trong giếng ẩn chứa càn khôn nhật nguyệt, tinh không vô tận; mặt nước có khả năng huyễn hóa, sao chép nguyên dạng chiêu thức đối phương."},{"id":"cung-dien-chuong-ton","name":"Cung điện Chưởng Tôn (thánh vật giới ngoại)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thánh vật","soHuu":["Chưởng Tôn"],"trangThai":"dang-co","blurb":"Cung điện Chưởng Tôn là thánh vật của giới ngoại, tồn tại từ thời viễn cổ, được mười vạn tu sĩ giới ngoại coi là biểu tượng tinh thần vĩnh viễn bất diệt. Cung điện gắn liền với sinh mệnh của Chưởng Tôn, dù bị phá nát vẫn có thể ngưng tụ phục hồi thông qua tam mệnh thuật.","detail":"Cung điện Chưởng Tôn là một kiến trúc cổ xưa, đóng vai trò vừa là trụ sở vừa là thánh vật tinh thần của giới ngoại, được mười vạn tu sĩ nơi đây tôn sùng và tin rằng vĩnh viễn không thể bị hủy diệt. Cung điện có mối liên hệ sinh mệnh trực tiếp với Chưởng Tôn giới ngoại — khi bị mũi tên của Vương Lâm phá nát, nó đã ngưng tụ trở lại cùng với Chưởng Tôn nhờ tam mệnh thuật. Sau khi phục hồi, Chưởng Tôn mang cung điện rút vào khe rồi biến mất @c1561.","congNang":["Là biểu tượng tinh thần và trụ sở của giới ngoại, được mười vạn tu sĩ tôn sùng","Gắn liền sinh mệnh với Chưởng Tôn, có thể bị phá hủy rồi ngưng tụ phục hồi thông qua tam mệnh thuật @c1561"],"chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1561","denChuong":"","cachCoDuoc":"Sở hữu từ xa xưa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1561","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị phá hủy rồi phục hồi","text":"Bị mũi tên Vương Lâm phá nát. Sau đó ngưng tụ trở lại cùng Chưởng Tôn nhờ tam mệnh thuật. Chưởng Tôn mang cung điện rút vào khe biến mất.","anchor":"Cung điện này chính là thánh vật, vĩnh viễn không thể bị hủy diệt!"}]},"nguon":["@c1561"],"dacDiem":"Cung điện cổ xưa được coi là vĩnh viễn bất diệt, có mối liên kết sinh mệnh với Chưởng Tôn giới ngoại, dù bị phá nát vẫn có thể tái ngưng tụ."},{"id":"ao-choang-dau-nguoi","name":"Áo choàng đầu người","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tấm áo choàng do đầu lâu tu sĩ giới ngoại bị Vương Lâm giết ngưng tụ phía sau hắn, không ngừng bành trướng khi hắn tiến vào đại quân.","detail":"Khi Vương Lâm xông vào giữa đại quân giới ngoại mở con đường máu, thân thể tu sĩ gặp hắn tan tành nhưng đầu lâu được bảo toàn, ngưng tụ phía sau hắn hình thành tấm áo choàng bằng đầu người. Số lượng đầu lâu tăng mạnh khi Vương Lâm tiến sâu, thể hiện khí thế hủy thiên diệt địa.","nguon":["@c1563"],"tabs":{"tienTrinh":[{"chuong":"@c1563","loai":"xuất hiện","importance":"normal","giaiDoan":"Quyết chiến giới ngoại","text":"Đầu lâu tu sĩ giới ngoại bị giết ngưng tụ phía sau Vương Lâm hình thành áo choàng đầu người, không ngừng bành trướng.","anchor":"Áo choàng này khi Vương Lâm tiến vào liền không ngừng bành trướng ra, số lượng đầu lâu tăng mạnh!"}]}},{"id":"banh-xe-van-menh","name":"Bánh xe vận mệnh","aliases":["Bánh xe tam đại bổn nguyên"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vương Lâm"],"trangThai":"Đã dùng hết, không thể tái tạo","blurb":"Bánh xe vận mệnh do tam đại hư bổn nguyên — Sinh Tử, Chân Giả, Nhân Quả — ngưng tụ thành, là pháp bảo cả đời Vương Lâm chỉ có thể ngưng tụ được một chiếc duy nhất. Khi vận hành, bánh xe bành trướng sánh ngang bầu trời, uy lực huỷ diệt khiến tinh không sụp đổ.","detail":"Bánh xe vận mệnh được hình thành từ ba bánh xe Sinh Tử, Chân Giả và Nhân Quả chồng lên nhau. Khi vận hành, nguyên thần của Vương Lâm tọa trấn bên trong làm trận linh. Bánh xe chỉ có thể ngưng tụ một lần duy nhất trong đời, sau khi sử dụng xong không thể ngưng tụ lần thứ hai. Trong trận chiến với tu sĩ giới ngoại, bánh xe bành trướng tới quy mô sánh ngang bầu trời, quay bốn vòng quét sạch hơn mười vạn tu sĩ, khiến tinh không sụp đổ.","capNhatToi":"@c1565","tabs":{"tienTrinh":[{"chuong":"@c1565","loai":"dung","importance":"major","giaiDoan":"Thi triển duy nhất — quay bốn vòng quét sạch La Thiên","text":"Bánh xe bành trướng sánh ngang bầu trời, quay bốn vòng quét sạch hơn mười vạn tu sĩ giới ngoại, tinh không sụp đổ. Sau khi dùng, Vương Lâm mang bánh xe bay đi, không thể tái tạo.","anchor":"Cả đời này hắn chỉ có thể ngưng tụ một bánh xe này"}]},"nguon":["@c1565"],"uyLuc":"Quay bốn vòng quét sạch hơn mười vạn tu sĩ giới ngoại, khiến tinh không sụp đổ @c1565","dacDiem":"Ba bánh xe Sinh Tử, Chân Giả, Nhân Quả chồng lên nhau tạo thành; cần nguyên thần tọa trấn làm trận linh khi vận hành; cả đời chỉ ngưng tụ được một chiếc duy nhất, dùng xong không thể ngưng tụ lần thứ hai","congNang":["Bành trướng sánh ngang bầu trời khi vận hành, quay bốn vòng quét sạch hơn mười vạn tu sĩ giới ngoại, khiến tinh không sụp đổ @c1565"]},{"id":"ngoc-gian-bao-mang-van-lac","name":"Ngọc giản bảo mạng của Vân Lạc đại ti","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vân Lạc đại ti"],"trangThai":"da-dung","blurb":"Ngọc giản bảo mạng do sư tôn của Vân Lạc đại ti trước khi chết tế luyện, dung hợp tinh không, có khả năng na di không giới hạn đưa chủ nhân về tế đàn tộc trong Thái Cổ Tinh Thần. Chỉ sử dụng được một lần rồi vỡ nát. Vân Lạc giữ nhiều năm nhưng tới chương 1566 mới bóp nát để thoát mạng.","detail":"Ngọc giản bảo mạng là pháp bảo cứu mạng do sư tôn của Vân Lạc đại ti trước khi chết đã tế luyện, dung hợp với tinh không. Pháp bảo này cho phép chủ nhân từ bất cứ nơi nào na di không giới hạn về tế đàn tộc trong Thái Cổ Tinh Thần, nhưng chỉ có thể dùng duy nhất một lần, sau đó vỡ nát. Vân Lạc đại ti giữ ngọc giản này nhiều năm, kể cả khi phân thân tử vong cũng chưa sử dụng. Tới khi Vương Lâm đánh tan chưởng của Chưởng Tôn, Vân Lạc mới bóp nát ngọc giản bảo mạng để na di về tế đàn tộc, thoát khỏi nguy cơ chí mạng.","congNang":["Na di không giới hạn, đưa chủ nhân từ bất cứ nơi nào về tế đàn tộc trong Thái Cổ Tinh Thần; chỉ dùng được một lần rồi vỡ nát @c1566"],"chuSoHuu":[{"ten":"Vân Lạc đại ti","tuChuong":"@c1566","denChuong":"@c1566","cachCoDuoc":"Sư tôn tế luyện trước khi chết lưu lại","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1566","loai":"dùng","importance":"major","giaiDoan":"Bóp nát để thoát mạng khỏi bánh xe vận mệnh","text":"Vân Lạc đại ti bóp nát ngọc giản bảo mạng khi Vương Lâm đánh tan chưởng Chưởng Tôn, na di về tế đàn tộc trong Thái Cổ Tinh Thần, thoát mạng dưới bánh xe vận mệnh.","anchor":"dung hợp với tinh không, có thể na di không giới hạn, có thể cho nàng từ bất cứ địa phương nào trong nháy mắt đều trở về được tế đàn của tộc"}]},"nguon":["@c1566"]},{"id":"truong-thuong-sam-set","name":"Trường thương sấm sét","cn":"","category":"linh-khi","categoryLabel":"Linh khí / Thánh vật","phamCap":"Thánh vật","soHuu":["Thiểm Lôi tộc"],"trangThai":"bi-huy-diet","blurb":"Thánh vật của Thiểm Lôi tộc, thanh trường thương hư ảo do sấm sét biến thành, ẩn chứa lực lượng sấm sét vô tận. Là trận linh thứ nhất của Phong Giới Đại Trận, bị Vương Lâm rút ra và hủy diệt.","detail":"Thanh trường thương hư ảo do sấm sét biến thành, ẩn chứa lực lượng sấm sét vô tận. Bị dung nhập vào Phong Giới Đại Trận từ vô số năm trước. Khi bị Nhân Quả trừu linh rút ra, tia chớp lan khắp mấy trăm ngàn dặm, cuối cùng bị hủy diệt.","congNang":["Lực lượng sấm sét vô tận"],"nguon":["@c1568"]},{"id":"ngoc-boi-chu-tien","name":"Ngọc bội chữ tiên","cn":"","aliases":["Trận linh thứ chín","Cửu linh"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Trận linh cuối cùng (mạnh nhất) của Phong Giới Đại Trận","soHuu":[],"trangThai":"Bị phá hủy (vỡ thành năm mảnh)","blurb":"Ngọc bội chữ tiên là cửu linh — trận linh thứ chín và mạnh nhất — trong chín trận linh duy trì Phong Giới Đại Trận. Trên bề mặt khắc một chữ tiên nét bút đơn giản cùng khoảng mười vết nứt cổ xưa. Bị Vương Lâm dùng Nhân Quả ấn lôi ra khỏi đại trận, ngọc bội vỡ thành năm mảnh khiến Phong Giới Đại Trận hoàn toàn tan rã, giới nội giới ngoại hợp nhất.","detail":"Ngọc bội chữ tiên là trận linh cốt lõi cuối cùng của Phong Giới Đại Trận, giữ vai trò then chốt trong việc duy trì vận hành toàn bộ đại trận. Trên ngọc bội khắc một chữ \"tiên\" với nét bút đơn giản. Bề mặt có khoảng mười vết nứt, trong đó một vết mới khoảng trăm năm, phần còn lại rất cổ xưa, cho thấy đại trận đã từng nhiều lần bị tấn công qua lịch sử lâu dài. Linh hồn Phong Tôn đời đầu dung nhập vào trận linh này để điều khiển Phong Giới Đại Trận; khi Phong Tôn hoàn toàn tử vong, trận linh mất đi sinh cơ. Vương Lâm thi triển Nhân Quả ấn lần cuối cùng lôi ngọc bội ra khỏi đại trận, ngọc bội rời khỏi đại trận liền vỡ thành năm mảnh, dẫn tới Phong Giới Đại Trận hoàn toàn tan rã, giới nội và giới ngoại hợp nhất.","congNang":["Là trận nhãn và trận linh cốt lõi duy trì Phong Giới Đại Trận, giữ cho đại trận vận hành @c1569","Được Phong Tôn đời đầu dung nhập linh hồn vào để điều khiển toàn bộ đại trận @c1569"],"chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c1569","loai":"xuat-hien","importance":"major","giaiDoan":"Bị lôi ra và phá hủy","text":"Vương Lâm thi triển Nhân Quả ấn lần cuối cùng lôi ngọc bội chữ tiên ra khỏi Phong Giới Đại Trận. Ngọc bội có khoảng mười vết nứt, khắc chữ tiên nét bút đơn giản. Rời khỏi đại trận liền vỡ thành năm mảnh, Phong Giới Đại Trận hoàn toàn tan rã.","anchor":"Chỉ là dù trên ngọc bội có nhiều vết nứt nhưng vẫn có thể thấy có một chữ được khắc trên đó. Chữ này nét bút đơn giản, bất ngờ là một chữ \"tiên\""}]},"nguon":["@c1569"],"uyLuc":"Khi ngọc bội bị lôi ra và vỡ thành năm mảnh, Phong Giới Đại Trận — đại trận phong tỏa cả một thế giới — hoàn toàn tan rã, giới nội giới ngoại hợp nhất @c1569.","dacDiem":"Trên bề mặt khắc một chữ \"tiên\" nét bút đơn giản, có khoảng mười vết nứt trong đó một vết mới khoảng trăm năm, phần còn lại rất cổ xưa."},{"id":"vien-co-bi-chieu","name":"Viễn cổ bí chiếu","cn":"远古秘诏","category":"khac","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Trường Tôn hội"],"trangThai":"Trong bảo khố, được lệnh lấy ra","blurb":"Bảo vật cất trong bảo khố Trường Tôn hội, cần dùng máu mười vạn tu sĩ để viết chiếu viễn cổ.","detail":"Chưởng Tôn ra lệnh mở bảo khố Trường Tôn hội lấy viễn cổ bí chiếu, dùng máu mười vạn tu sĩ viết chiếu viễn cổ nhằm phục vụ chiến dịch phá trận pháp giới nội trong ba năm. Công năng cụ thể chưa được tiết lộ.","nguon":["@c1572"]},{"id":"cay-cung-ly-quang","name":"Cây cung Lý Quảng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cây cung Lý Quảng là pháp bảo do đạo nhân bảy màu trao cho Chưởng Tôn sử dụng trong trận đánh giới nội–giới ngoại Thái Cổ Tinh Thần. Sau khi Chưởng Tôn thất bại, cây cung rơi vào tay Vương Lâm và được hắn giữ lại làm hậu thủ.","detail":"Cây cung Lý Quảng vốn thuộc về Lý Quảng, được đạo nhân bảy màu (sư tôn của Chưởng Tôn) cho Chưởng Tôn mượn dùng nhằm áp đảo giới nội Thái Cổ Tinh Thần trong cuộc chiến giữa giới nội và giới ngoại. Tuy nhiên, Chưởng Tôn thất bại trong trận đánh này, cây cung đã rơi vào tay Vương Lâm; sự kiện Chưởng Tôn bẩm báo mất cây cung được ghi nhận tại @c1573. Về sau, Vương Lâm coi cây cung là một hậu thủ quan trọng, dù không muốn tùy tiện sử dụng nhưng sẵn sàng xuất ra khi lâm vào nguy cấp @c1646.","congNang":["Áp đảo giới nội Thái Cổ Tinh Thần @c1573","Được Vương Lâm giữ làm hậu thủ, dự bị sử dụng trong tình huống nguy cấp @c1646"],"chuSoHuu":[{"ten":"Lý Quảng","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"không rõ"},{"ten":"Chưởng Tôn","tuChuong":"","denChuong":"@c1573","cachCoDuoc":"Được sư tôn (đạo nhân bảy màu) cho mượn","trangThai":"đã mất"},{"ten":"Vương Lâm","tuChuong":"@c1573","denChuong":"","cachCoDuoc":"Đoạt được sau trận đánh giới nội-giới ngoại","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1573","loai":"đổi chủ","importance":"major","giaiDoan":"Rơi vào tay Vương Lâm","text":"Chưởng Tôn bẩm báo cây cung Lý Quảng đã rơi vào tay Vương Lâm sau thất bại trong trận đánh giới nội-giới ngoại.","anchor":"cây cung của Lý Quảng sư tôn cho đệ tử dùng áp đảo giới nội lúc này đã rơi vào tay Vương Lâm"}]},"nguon":["@c1573"]},{"id":"chien-xa-ngan-truong","name":"Chiến xa ngàn trượng","cn":"","category":"phap-bao","categoryLabel":"Chiến cụ","phamCap":"Không rõ","soHuu":["Đại quân giới ngoại"],"trangThai":"dang-co","blurb":"Chiến xa lớn ngàn trượng của đại quân giới ngoại, được nhiều tu sĩ đẩy đi, xé gió vọt tới với tiếng ầm ầm như sấm sét.","detail":"Chiến cụ khổng lồ trong đội hình mười vạn tu sĩ giới ngoại tấn công nơi Vương Lâm trấn thủ.","congNang":["Chiến cụ tấn công quy mô lớn của đại quân giới ngoại"],"tabs":{"tienTrinh":[{"chuong":"@c1573","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trong đại quân giới ngoại","text":"Chiến xa ngàn trượng xuất hiện trong đội hình mười vạn tu sĩ giới ngoại tấn công lần nữa vào nơi Vương Lâm trấn thủ.","anchor":"một chiến xa lớn ngàn trượng, được rất nhiều tu sĩ đẩy đi, xé gió vọt tới"}]},"nguon":["@c1573"]},{"id":"bia-da-chin-quan-tai","name":"Bia đá mấy ngàn trượng và chín quan tài","cn":"","aliases":[],"category":"khac","categoryLabel":"Chiến cụ","phamCap":"","soHuu":["Giới ngoại"],"trangThai":"dang-co","blurb":"Chiến cụ tập thể giới ngoại: bia đá lớn mấy ngàn trượng tỏa khí tức hỗn tạp, trên bia có chín sợi xích sắt, mỗi đầu xích nối một quan tài khổng lồ trăm trượng, trông từ xa như bạch tuộc.","detail":"Tấm bia đá mấy ngàn trượng do mấy ngàn tu sĩ khiêng bay, tỏa khí tức hỗn tạp. Trên bia có chín sợi xích sắt kéo dài, mỗi đầu xích nối một cái quan tài khổng lồ trăm trượng. Từ xa trông như bạch tuộc khổng lồ. Là một phần lực lượng cực hạn cuối cùng của giới ngoại.","hinhDang":"Bia đá mấy ngàn trượng, chín sợi xích sắt nối chín quan tài trăm trượng, trông như bạch tuộc","nguonGoc":"Chiến cụ giới ngoại","congNang":[],"chuSoHuu":[{"ten":"Giới ngoại","tuChuong":"@c1574","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1574","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trong tổng công kích","text":"Bia đá mấy ngàn trượng cùng chín quan tài khổng lồ xuất hiện phía sau mười vạn tu sĩ giới ngoại, do mấy ngàn tu sĩ khiêng bay, là một phần lực lượng cực hạn cuối cùng.","anchor":"trên tấm bia đá này có chín sợi xích sắt kéo dài ra, mỗi đầu xích là một cái quan tài khổng lồ"}]},"nguon":["@c1574"]},{"id":"chien-xa-vien-co-manh-thu","name":"Chiến xa viễn cổ mãnh thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Trường Tôn hội","soHuu":["Trường Tôn hội"],"trangThai":"dang-co","blurb":"Hơn mười chiếc chiến xa bọc da thú dữ tợn của Trường Tôn hội, mỗi chiếc trấn áp hồn phách một viễn cổ mãnh thú có tổ tiên từ Tiên Cương đại lục. Được triển khai để tấn công Vô Danh Chuyển Luân trận, sử dụng tu sĩ cảm tử làm mồi kích hoạt hồn phách mãnh thú đồng loạt xuất kích.","detail":"Chiến xa bọc da thú, mỗi chiếc trấn áp hồn phách một viễn cổ mãnh thú — tổ tiên của chúng do Thất Thải Tiên Tôn mang từ Tiên Cương đại lục tới, sinh sôi trong thế giới động phủ, vốn là tiên thú đẳng cấp khác nhau. Trên chiến xa có cánh tay bắn đá dùng để phóng tu sĩ cảm tử. Mãnh thú được trấn áp trên xe gồm trường long vạn trượng, thú hình dạng kỳ dị, và cả Cát Cùng. Tu sĩ cảm tử bị bắn tung hóa thành lưu tinh tử vong, lấy hình thần câu diệt đánh lên trận pháp; khí tức tử vong cùng hồn lực tích tụ hình thành ký hiệu quỷ dị, hấp dẫn hồn phách mãnh thú thức tỉnh để đồng loạt tấn công mục tiêu. Cơ chế hoạt động giống hệt trận linh trong Phong Giới Đại Trận năm xưa nhưng không có lửa. Là chí bảo của Trường Tôn hội, được triển khai hơn mười chiếc trong trận chiến công phá Vô Danh Chuyển Luân tr","congNang":["Bắn tu sĩ cảm tử lên trận pháp; khí tức tử vong và hồn lực tích tụ hình thành ký hiệu quỷ dị hút hồn phách mãnh thú thức tỉnh @c1575","Giải phóng hồn phách viễn cổ mãnh thú đồng loạt tấn công mục tiêu @c1575"],"chuSoHuu":[{"ten":"Trường Tôn hội","tuChuong":"@c1575","denChuong":"","cachCoDuoc":"Chí bảo của hội, luyện chế từ vô số tài liệu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1575","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện trên chiến trường","text":"Hơn mười chiếc chiến xa được đẩy tới tấn công Vô Danh Chuyển Luân trận. Tu sĩ cảm tử bị bắn tung tạo ký hiệu quỷ dị trên trận pháp, kích hoạt mãnh thú thức tỉnh đồng loạt lao vào tấn công, khiến trận pháp chấn động run rẩy.","anchor":"trọng yếu nhất đó là trên mỗi chiếc chiến xa đều có một hồn phách viễn cổ mãnh thú bị trấn áp"}]},"nguon":["@c1575"],"dacDiem":"Chiến xa bọc da thú, mỗi chiếc trấn áp hồn phách một viễn cổ mãnh thú; có cánh tay bắn đá phóng tu sĩ cảm tử; mãnh thú trên xe gồm trường long vạn trượng, thú hình dạng kỳ dị và Cát Cùng; cơ chế tương tự trận linh trong Phong Giới Đại Trận nhưng không có lửa."},{"id":"chin-quan-tai-thai-co-hoang-than","name":"Chín quan tài Thái cổ hoàng thần","cn":"","aliases":["Tấm bia đá chín quan tài","Thái cổ hoàng thần"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Giới ngoại"],"trangThai":"da-mo","blurb":"Chín quan tài Thái cổ hoàng thần là vũ khí cuối cùng mà giới ngoại mang theo trong cuộc xâm lược, phong ấn thân thể chia chín phần của Thái cổ hoàng thần bên trong chín quan tài gắn liền với một tấm bia đá khổng lồ qua chín sợi xích sắt. Khi được kích hoạt bằng nguyên thần tinh huyết của năm bậc toàn năng cùng mấy vạn tu sĩ giới ngoại, chín quan tài vỡ tan hợp nhất giải phóng luồng khí tức Đạo cổ biến đổi giữa Cổ Thần, Cổ Ma và Cổ Yêu, được Vương Lâm nhận ra thuộc về Diệp Mịch.","detail":"Tấm bia đá khổng lồ mang chín ký hiệu, mỗi ký hiệu nối một sợi xích sắt dẫn tới một trong chín quan tài, tạo thành chỉnh thể phong ấn thân thể chia chín phần của Thái cổ hoàng thần. Giới ngoại coi đây là lực lượng bảo vệ Thái cổ Tinh Thần, gọi là hồn phách bất tử khi hợp nhất. Khi khai phong, chín ký hiệu trên bia đá đồng loạt lóe sáng, truyền khí tức qua xích sắt khiến chín quan tài mở tung; tóc đen dài yêu dị lan ra từ bên trong tràn ngập tinh không. Năm bậc toàn năng và mấy vạn tu sĩ giới ngoại quỳ bái phun nguyên thần tinh huyết để chín quan tài hấp thu, hoàn tất quá trình hợp nhất. Sau khi vỡ tan, bùng lên luồng khí tức Đạo cổ biến đổi giữa Cổ Thần, Cổ Ma và Cổ Yêu. Vương Lâm nhận ra khí tức này thuộc về Diệp Mịch và phán đoán đây không phải mắt trái của Diệp Mịch.","congNang":["Phong ấn thân thể chia chín phần của Thái cổ hoàng thần bên trong chín quan tài, duy trì trạng thái phong ấn qua hệ thống bia đá – xích sắt – quan tài @c1576","Khi kích hoạt bằng nguyên thần tinh huyết của đông đảo tu sĩ và bậc toàn năng, chín quan tài hấp thu tinh huyết rồi vỡ tan, hợp nhất thân thể chia chín phần và giải phóng lực lượng Đạo cổ @c1576"],"hinhDang":"Tấm bia đá khổng lồ mang chín ký hiệu, chín sợi xích sắt nối chín quan tài; bên trong quan tài chứa tóc đen dài yêu dị","nguonGoc":"Được giới ngoại mang theo như vũ khí cuối cùng trong cuộc xâm lược","dacDiem":"Chín quan tài gắn liền với tấm bia đá qua chín sợi xích sắt; khi mở, tóc đen dài yêu dị lan ra tràn ngập tinh không; khí tức Đạo cổ giải phóng liên tục biến đổi giữa ba dạng Cổ Thần, Cổ Ma, Cổ Yêu, thuộc về Diệp Mịch.","chuHienThoi":"Giới ngoại","capNhatToi":"@c1576","chuSoHuu":[{"ten":"Giới ngoại","tuChuong":"@c1576","denChuong":"","cachCoDuoc":"Mang theo từ giới ngoại","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1576","loai":"khai phong","importance":"major","giaiDoan":"Chín quan tài mở tung giải phóng Đạo cổ Diệp Mịch","text":"Chín ký hiệu trên bia đá lóe sáng truyền khí tức qua xích sắt vào chín quan tài, mở tung chúng. Năm bậc toàn năng và mấy vạn tu sĩ phun nguyên thần tinh huyết hiến tế. Chín quan tài vỡ tan bùng lên lực lượng Đạo cổ biến đổi Cổ Thần – Cổ Ma – Cổ Yêu thuộc về Diệp Mịch.","anchor":"Thái cổ hoàng thần bảo vệ Thái cổ Tinh Thần qua bao năm tháng, thân thể người chia làm chín phần, hôm nay chín phần hợp làm một"}]},"dinhDanh":"goc","nguon":["@c1576"],"uyLuc":"Sau khi hợp nhất, bùng lên luồng khí tức Đạo cổ biến đổi giữa Cổ Thần, Cổ Ma và Cổ Yêu, tràn ngập tinh không, cần năm bậc toàn năng cùng mấy vạn tu sĩ giới ngoại hiến nguyên thần tinh huyết mới kích hoạt được."},{"id":"chin-quan-tai-chi-bao-truong-ton-hoi","name":"Chín quan tài (chí bảo Trường Tôn hội)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Chí bảo","soHuu":["Chưởng Tôn","Trường Tôn hội"],"trangThai":"da-dung","blurb":"Chín quan tài là chí bảo của Trường Tôn hội, do Chưởng Tôn và đạo nhân bảy màu hợp tạo trải qua năm tháng vô tận. Mỗi quan tài phong ấn một phần thân thể, khi giải phóng toàn bộ sẽ hợp nhất thành chiến binh ngàn trượng mang khí tức Đạo cổ Diệp Mịch tinh thuần.","detail":"Chín quan tài chứa chín phần thân thể của một nam tử trung niên — gồm hai tay, hai chân, bốn phần thân và một đầu. Bảo vật này do Chưởng Tôn cùng đạo nhân bảy màu tạo nên qua năm tháng vô tận, được liệt vào hàng chí bảo của Trường Tôn hội. Chưởng Tôn coi đây là vật quan trọng cho tương lai, chỉ xuất ra khi vạn bất đắc dĩ, từng gây nhiều lần sát lục. Tại chương @c1577, chín quan tài lần lượt nổ tung, chín phần thân thể dung hợp thành nam tử trung niên ngàn trượng mang khí tức Đạo cổ Diệp Mịch tinh thuần. Lần xuất thế này nhằm bức ép Vương Lâm phải bắn tên Xạ Thần xa.","nguonGoc":"Chưởng Tôn và đạo nhân bảy màu hợp tạo qua năm tháng vô tận","congNang":["Phong ấn chín phần thân thể (hai tay, hai chân, bốn phần thân, một đầu) riêng biệt trong chín quan tài","Khi giải phóng, chín phần thân thể dung hợp thành chiến binh nam tử trung niên ngàn trượng mang khí tức Đạo cổ Diệp Mịch tinh thuần @c1577","Chiến binh hợp nhất sở hữu hai tinh điểm Cổ Thần, ba yêu tinh, ba ma tinh"],"chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1577","denChuong":"","cachCoDuoc":"Cùng đạo nhân bảy màu tạo nên","trangThai":"da-dung"},{"ten":"Trường Tôn hội","tuChuong":"@c1577","denChuong":"","cachCoDuoc":"Chí bảo của hội","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1577","loai":"xuất hiện","importance":"major","giaiDoan":"Nổ tung hợp nhất thành nam tử trung niên","text":"Chín quan tài lần lượt nổ tung, chín phần thân thể dung hợp thành nam tử trung niên ngàn trượng mang khí tức Đạo cổ Diệp Mịch. Chưởng Tôn tiết lộ đây là chí bảo Trường Tôn hội, xuất ra để bức Vương Lâm bắn tên Xạ Thần xa.","anchor":"Vật này là trải qua năm tháng vô tận được hắn và đạo nhân bảy màu tạo nên cuối cùng ngưng tụ thành","phamCap":"Chí bảo"}]},"nguon":["@c1577"],"uyLuc":"Hợp nhất thành chiến binh ngàn trượng mang khí tức Đạo cổ tinh thuần, sở hữu hai tinh điểm Cổ Thần cùng ba yêu tinh và ba ma tinh, đủ sức bức Vương Lâm phải dùng tới tên Xạ Thần xa.","dacDiem":"Gồm chín quan tài riêng biệt, mỗi chiếc chứa một phần thân thể; được Chưởng Tôn coi là vật quan trọng cho tương lai, chỉ xuất ra khi vạn bất đắc dĩ, từng gây nhiều lần sát lục."}]};
